window.THEATER_SCRIPT={"title":"Die Räuber","author":"Friedrich Schiller","paragraphCount":1457,"pageCount":63,"physicalPageCount":64,"acts":[{"text":"ERSTER AKT","index":4,"page":1},{"text":"ZWEITER AKT","index":395,"page":19},{"text":"DRITTER AKT","index":775,"page":35},{"text":"VIERTER AKT","index":934,"page":42},{"text":"FÜNFTER AKT","index":1230,"page":55}],"scenes":[{"text":"1. SZENE","index":5,"page":1,"act":"ERSTER AKT"},{"text":"2. SZENE","index":125,"page":7,"act":"ERSTER AKT"},{"text":"3. SZENE","index":344,"page":16,"act":"ERSTER AKT"},{"text":"1. SZENE","index":396,"page":19,"act":"ZWEITER AKT"},{"text":"2. SZENE","index":474,"page":23,"act":"ZWEITER AKT"},{"text":"3. SZENE","index":618,"page":28,"act":"ZWEITER AKT"},{"text":"1. SZENE","index":776,"page":35,"act":"DRITTER AKT"},{"text":"2. SZENE","index":841,"page":38,"act":"DRITTER AKT"},{"text":"1. SZENE","index":935,"page":42,"act":"VIERTER AKT"},{"text":"2. SZENE","index":946,"page":43,"act":"VIERTER AKT"},{"text":"3. SZENE","index":992,"page":45,"act":"VIERTER AKT"},{"text":"4. SZENE","index":1037,"page":47,"act":"VIERTER AKT"},{"text":"5. SZENE","index":1075,"page":49,"act":"VIERTER AKT"},{"text":"1. SZENE","index":1231,"page":55,"act":"FÜNFTER AKT"},{"text":"2. SZENE","index":1329,"page":59,"act":"FÜNFTER AKT"}],"pages":[{"page":1,"firstIndex":4,"lastIndex":29,"act":"ERSTER AKT","scene":null},{"page":2,"firstIndex":30,"lastIndex":47,"act":"ERSTER AKT","scene":"1. SZENE"},{"page":3,"firstIndex":48,"lastIndex":59,"act":"ERSTER AKT","scene":"1. SZENE"},{"page":4,"firstIndex":60,"lastIndex":87,"act":"ERSTER AKT","scene":"1. SZENE"},{"page":5,"firstIndex":88,"lastIndex":112,"act":"ERSTER AKT","scene":"1. SZENE"},{"page":6,"firstIndex":113,"lastIndex":124,"act":"ERSTER AKT","scene":"1. SZENE"},{"page":7,"firstIndex":125,"lastIndex":148,"act":"ERSTER AKT","scene":"2. SZENE"},{"page":8,"firstIndex":149,"lastIndex":170,"act":"ERSTER AKT","scene":"2. SZENE"},{"page":9,"firstIndex":171,"lastIndex":195,"act":"ERSTER AKT","scene":"2. SZENE"},{"page":10,"firstIndex":196,"lastIndex":226,"act":"ERSTER AKT","scene":"2. SZENE"},{"page":11,"firstIndex":227,"lastIndex":253,"act":"ERSTER AKT","scene":"2. SZENE"},{"page":12,"firstIndex":254,"lastIndex":279,"act":"ERSTER AKT","scene":"2. SZENE"},{"page":13,"firstIndex":280,"lastIndex":304,"act":"ERSTER AKT","scene":"2. SZENE"},{"page":14,"firstIndex":305,"lastIndex":333,"act":"ERSTER AKT","scene":"2. SZENE"},{"page":15,"firstIndex":334,"lastIndex":343,"act":"ERSTER AKT","scene":"2. SZENE"},{"page":16,"firstIndex":344,"lastIndex":366,"act":"ERSTER AKT","scene":"3. SZENE"},{"page":17,"firstIndex":367,"lastIndex":384,"act":"ERSTER AKT","scene":"3. SZENE"},{"page":18,"firstIndex":385,"lastIndex":394,"act":"ERSTER AKT","scene":"3. SZENE"},{"page":19,"firstIndex":395,"lastIndex":415,"act":"ZWEITER AKT","scene":null},{"page":20,"firstIndex":416,"lastIndex":445,"act":"ZWEITER AKT","scene":"1. SZENE"},{"page":21,"firstIndex":446,"lastIndex":465,"act":"ZWEITER AKT","scene":"1. SZENE"},{"page":22,"firstIndex":466,"lastIndex":473,"act":"ZWEITER AKT","scene":"1. SZENE"},{"page":23,"firstIndex":474,"lastIndex":505,"act":"ZWEITER AKT","scene":"2. SZENE"},{"page":24,"firstIndex":506,"lastIndex":533,"act":"ZWEITER AKT","scene":"2. SZENE"},{"page":25,"firstIndex":534,"lastIndex":557,"act":"ZWEITER AKT","scene":"2. SZENE"},{"page":26,"firstIndex":558,"lastIndex":589,"act":"ZWEITER AKT","scene":"2. SZENE"},{"page":27,"firstIndex":590,"lastIndex":617,"act":"ZWEITER AKT","scene":"2. SZENE"},{"page":28,"firstIndex":618,"lastIndex":628,"act":"ZWEITER AKT","scene":"3. SZENE"},{"page":29,"firstIndex":629,"lastIndex":654,"act":"ZWEITER AKT","scene":"3. SZENE"},{"page":30,"firstIndex":655,"lastIndex":682,"act":"ZWEITER AKT","scene":"3. SZENE"},{"page":31,"firstIndex":683,"lastIndex":703,"act":"ZWEITER AKT","scene":"3. SZENE"},{"page":32,"firstIndex":704,"lastIndex":729,"act":"ZWEITER AKT","scene":"3. SZENE"},{"page":33,"firstIndex":730,"lastIndex":757,"act":"ZWEITER AKT","scene":"3. SZENE"},{"page":34,"firstIndex":758,"lastIndex":774,"act":"ZWEITER AKT","scene":"3. SZENE"},{"page":35,"firstIndex":775,"lastIndex":797,"act":"DRITTER AKT","scene":null},{"page":36,"firstIndex":798,"lastIndex":822,"act":"DRITTER AKT","scene":"1. SZENE"},{"page":37,"firstIndex":823,"lastIndex":840,"act":"DRITTER AKT","scene":"1. SZENE"},{"page":38,"firstIndex":841,"lastIndex":872,"act":"DRITTER AKT","scene":"2. SZENE"},{"page":39,"firstIndex":873,"lastIndex":904,"act":"DRITTER AKT","scene":"2. SZENE"},{"page":40,"firstIndex":905,"lastIndex":925,"act":"DRITTER AKT","scene":"2. SZENE"},{"page":41,"firstIndex":926,"lastIndex":933,"act":"DRITTER AKT","scene":"2. SZENE"},{"page":42,"firstIndex":934,"lastIndex":945,"act":"VIERTER AKT","scene":null},{"page":43,"firstIndex":946,"lastIndex":980,"act":"VIERTER AKT","scene":"2. SZENE"},{"page":44,"firstIndex":981,"lastIndex":991,"act":"VIERTER AKT","scene":"2. SZENE"},{"page":45,"firstIndex":992,"lastIndex":1011,"act":"VIERTER AKT","scene":"3. SZENE"},{"page":46,"firstIndex":1012,"lastIndex":1036,"act":"VIERTER AKT","scene":"3. SZENE"},{"page":47,"firstIndex":1037,"lastIndex":1067,"act":"VIERTER AKT","scene":"4. SZENE"},{"page":48,"firstIndex":1068,"lastIndex":1074,"act":"VIERTER AKT","scene":"4. SZENE"},{"page":49,"firstIndex":1075,"lastIndex":1103,"act":"VIERTER AKT","scene":"5. SZENE"},{"page":50,"firstIndex":1104,"lastIndex":1130,"act":"VIERTER AKT","scene":"5. SZENE"},{"page":51,"firstIndex":1131,"lastIndex":1163,"act":"VIERTER AKT","scene":"5. SZENE"},{"page":52,"firstIndex":1164,"lastIndex":1196,"act":"VIERTER AKT","scene":"5. SZENE"},{"page":53,"firstIndex":1197,"lastIndex":1213,"act":"VIERTER AKT","scene":"5. SZENE"},{"page":54,"firstIndex":1214,"lastIndex":1229,"act":"VIERTER AKT","scene":"5. SZENE"},{"page":55,"firstIndex":1230,"lastIndex":1259,"act":"FÜNFTER AKT","scene":null},{"page":56,"firstIndex":1260,"lastIndex":1290,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"page":57,"firstIndex":1291,"lastIndex":1324,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"page":58,"firstIndex":1325,"lastIndex":1328,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"page":59,"firstIndex":1329,"lastIndex":1365,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"page":60,"firstIndex":1366,"lastIndex":1396,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"page":61,"firstIndex":1397,"lastIndex":1421,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"page":62,"firstIndex":1422,"lastIndex":1449,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"page":63,"firstIndex":1450,"lastIndex":1456,"act":"FÜNFTER AKT","scene":"2. SZENE"}],"source":{"docx":"Theater.Text.Neu.formatiert.docx","renderedPages":64},"paragraphs":[{"text":"FRIEDRICH SCHILLER","type":"cover","page":0,"act":null,"scene":null},{"text":"DIE RÄUBER","type":"cover","page":0,"act":null,"scene":null},{"text":"Bühnenmanuskript für die Theater-AG","type":"cover","page":0,"act":null,"scene":null},{"text":"Einheitlich gesetzte Arbeitsfassung","type":"cover","page":0,"act":null,"scene":null},{"text":"ERSTER AKT","type":"act","page":1,"act":"ERSTER AKT","scene":null},{"text":"1. SZENE","type":"scene","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Saal im Moorischen Schloss.","type":"setting","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Franz, der alte Moor.","type":"setting","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Aber ist Euch auch wohl, Vater? Ihr seht so blass.","type":"dialogue","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Ganz wohl, mein Sohn, – was hattest du mir zu sagen?","type":"dialogue","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Die Post ist angekommen – ein Brief von unserm Korrespondenten in Leipzig –","type":"dialogue","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR  (begierig)","type":"speaker","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Nachrichten von meinem Sohne Karl?","type":"dialogue","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Hm! Hm! – So ist es. Aber ich fürchte – ich weiß nicht – ob ich – Eurer Gesundheit? – Ist Euch wirklich ganz wohl, mein Vater?","type":"dialogue","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Wie ein Fisch im Wasser! Von meinem Sohne schreibt er? – Wie kommst du zu dieser Besorgnis? Du hast mich zweimal gefragt.","type":"dialogue","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Wenn Ihr krank seid – nur die leiseste Ahnung habt, es zu werden, so lasst mich – ich will zu gelegenerer Zeit zu Euch reden. (Halb zu sich.) Diese Zeitung ist nicht für einen zerbrechlichen Körper.","type":"dialogue","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Gott! was werde ich hören?","type":"dialogue","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Lasst mich vorerst auf die Seite gehn und eine Träne des Mitleids vergießen um meinen verlorenen Bruder – ich sollte schweigen auf ewig – denn er ist Euer Sohn; ich sollte seine Schande verhüllen auf ewig – denn er ist mein Bruder. – Aber Euch gehorchen, ist meine erste, traurige Pflicht – darum vergebt mir.","type":"dialogue","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"O Karl! Karl! wüsstest du, wie deine Aufführung das Vaterherz foltert! wie eine einzige frohe Nachricht von dir meinem Leben zehn Jahre zusetzen würde – mich zum Jüngling machen würde – da mich nun jede, ach! – einen Schritt näher ans Grab rückt!","type":"dialogue","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Ist es das, alter Mann, so lebt wohl – wir alle würden noch heute die Haare ausraufen über Eurem Sarge.","type":"dialogue","page":1,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Bleib! – Es ist noch, um den kleinen kurzen Schritt zu tun – lass ihm seinen Willen! Lies!","type":"dialogue","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ  (nimmt den Brief aus der Tasche)","type":"speaker","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Ihr kennt unsern Korrespondenten! Seht! den Finger meiner rechten Hand wollt' ich drum geben, dürft' ich sagen, er ist ein Lügner, ein schwarzer, giftiger Lügner – – Fasst Euch! Ihr vergebt mir, wenn ich Euch den Brief nicht selbst lesen lasse – Noch dürft Ihr nicht Alles hören.","type":"dialogue","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Alles, Alles – mein Sohn.","type":"dialogue","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ  (liest)","type":"speaker","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"„Leipzig, vom 1sten Mai. – Verbände mich nicht die Zusage, dir auch nicht das Geringste zu verhehlen, was ich von den Schicksalen deines Bruders auffangen kann, liebster Freund, nimmermehr würde meine unschuldige Feder an dir zur Tyrannin geworden sein. Ich kann aus hundert Briefen von dir abnehmen, wie Nachrichten dieser Art dein brüderliches Herz durchbohren müssen“- Seht, Vater! ich lese Euch nur das Glimpflichste – „den Abscheulichen in tausend Tränen ergossen;« – Ach, sie flossen – stürzten stromweis von dieser mitleidigen Wange – »mir ist's, als säh' ich schon deinen alten, frommen Vater totenbleich« – Jesus Maria! Ihr seid's, eh' ihr noch das Mindeste wisst?","type":"dialogue","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Weiter! Weiter!","type":"dialogue","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"–","type":"dialogue","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"„totenbleich in seinen Stuhl zurücktaumeln und dem Tage fluchen, an dem ihm zum ersten Mal Vater entgegengestammelt ward. Man hat mir nicht Alles entdecken mögen, und von dem Wenigen, das ich weiß, erfährst du nur Weniges. Dein Bruder scheint nun das Maß seiner Schande erfüllt zu haben. Gestern um Mitternacht hatte er den großen Entschluss, nach vierzigtausend Dukaten Schulden« – ein hübsches Taschengeld, Vater – »nachdem er zuvor die Tochter eines reichen Bankiers allhier entjungfert und ihren Galan, einen braven Jungen von Stand, im Duell auf den Tod verwundet, mit sieben Andern, die er mit in sein Luderleben gezogen, dem Arm der Justiz zu entlaufen.« – Vater! Um Gotteswillen! Vater, wie wird Euch?","type":"dialogue","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Es ist genug. Lass ab, mein Sohn!","type":"dialogue","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Ich schone Eurer – „Man hat ihm Steckbriefe nachgeschickt, die Beleidigten schreien laut um Genugtuung, ein Preis ist auf seinen Kopf gesetzt – der","type":"dialogue","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Name Moor“ – Nein! meine armen Lippen sollen nimmermehr einen Vater ermorden! (Zerreißt den Brief.) Glaubt es nicht, Vater! glaubt ihm keine Silbe!","type":"dialogue","page":2,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR  (weint bitterlich)","type":"speaker","page":3,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Mein Name! Mein ehrlicher Name!","type":"dialogue","page":3,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ  (fällt ihm um den Hals.)","type":"speaker","page":3,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Schändlicher, dreimal schändlicher Karl! Ich ahnte es, da er, noch ein Knabe, den Mädels so nachschlenderte, mit Gassenjungen und elendem Gesindel auf Wiesen und Wegen sich herumhetzte, den Anblick der Kirche, wie ein Missetäter das Gefängnis, floh und die Pfennige, die er Euch abquälte, dem ersten dem besten Bettler in den Hut warf, während wir daheim mit frommen Gebeten und heiligen Predigtbüchern uns erbauten? – Hundertmal hab' ich's Euch geweissagt, denn meine Liebe zu ihm war immer in den Schranken der kindlichen Pflicht – der Junge wird uns alle noch in Elend und Schande stürzen! – O, dass er Moors Namen nicht trüge! dass mein Herz nicht so warm für ihn schlüge!","type":"dialogue","page":3,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":3,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Oh – meine Aussichten! Meine goldenen Träume!","type":"dialogue","page":3,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":3,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Das weiß ich wohl. Das ist es ja, was ich eben sagte. Diese schönen glänzenden Tugenden, die im Vatersöhnchen keimten, werden ihn dereinst zu einem warmen Freund eines Freundes, zu einem trefflichen Bürger, zu einem Helden, zu einem großen, großen Manne machen. – Seht Ihr's nun, Vater! – der feurige Geist hat sich entwickelt, ausgebreitet, herrliche Früchte hat er getragen. Seht diese Offenheit, wie hübsch sie sich zur Frechheit herumgedreht hat! sehet diese Weichheit, wie zärtlich sie für Koketten girret. Vielleicht, Vater, erlebt Ihr noch die Freude, ihn an der Fronte eines Heeres zu erblicken, das in der heiligen Stille der Wälder residieret und dem müden Wanderer seine Reise um die Hälfte der Bürde erleichtert. Vater, Vater – seht Euch nach einem anderen Namen um, sonst deuten Krämer und Gassenjungen mit Fingern auf Euch, die Euren Herrn Sohn auf dem Leipziger Marktplatz im Portrait gesehen haben.","type":"dialogue","page":3,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":3,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Und auch du, mein Franz, auch du? O meine Kinder! Wie sie nach meinem Herzen zielen!","type":"dialogue","page":3,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":3,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Ihr seht, ich kann auch witzig sein, aber mein Witz ist Skorpionstich. – Und dann der trockne Alltagsmensch, der kalte, hölzerne Franz, und wie die Titelchen alle heißen mögen, die Euch der Kontrast zwischen ihm und mir mocht' eingegeben haben, wenn er Euch auf dem Schoße saß, oder in die Backen zwickte – der wird einmal zwischen seinen Grenzsteinen sterben und modern und vergessen werden, wenn der Ruhm dieses Universalkopfs von einem Pole zum andern fliegt – Ha! mit gefaltnen Händen dankt dir, o Himmel! der kalte, trockne, hölzerne Franz – dass er nicht ist, wie dieser!","type":"dialogue","page":3,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Vergib mir, mein Sohn; zürne nicht auf einen Vater, der sich in seinen Planen betrogen findet.","type":"dialogue","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Du hast noch große Pflichten auf dir, mein Sohn – Gott segne dich für das, was du mir warst und sein wirst!","type":"dialogue","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Nun sagt mir einmal – wenn Ihr diesen Sohn nicht den Euren nennen müsstet, Ihr wärt ein glücklicher Mann?","type":"dialogue","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Stille! o stille! Bin ich nicht ein glücklicher Mann?","type":"dialogue","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Ihr habt Kummer, solang Ihr diesen Sohn habt. Dieser Kummer wird wachsen mit Karln. Dieser Kummer wird Euer Leben untergraben.","type":"dialogue","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Oh! er hat mich zu einem achtzigjährigen Manne gemacht.","type":"dialogue","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Nun also – wenn Ihr dieses Sohnes Euch entäußertet?","type":"dialogue","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR  (auffahrend)","type":"speaker","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Franz! Franz! was sagst du?","type":"dialogue","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Ist es nicht diese Liebe zu ihm, die Euch all den Gram macht? Ohne diese Liebe ist er für Euch nicht da. Ohne diese strafbare, diese verdammliche Liebe ist er Euch gestorben – ist er Euch nie geboren.","type":"dialogue","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Du willst, ich soll meinen Sohn verfluchen?","type":"dialogue","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Was heißt Ihr Euren Sohn? – dem Ihr das Leben gegeben habt, wenn er sich auch alle ersinnliche Mühe gibt, das Eurige zu verkürzen?","type":"dialogue","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Heißt Ihr das Euren Sohn? Antwortet! heißt Ihr das einen Sohn?","type":"dialogue","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Ein unzärtliches Kind! ach! aber mein Kind doch! mein Kind doch!","type":"dialogue","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"O dass Ihr's begreifen lernt, dass Euch die Schuppen fielen vom Auge! Aber Eure Nachsicht muss ihn in seinen Liederlichkeiten befestigen, Euer Vorschub ihnen Rechtmäßigkeit geben. Auf Euch, Vater, auf Euch wird der Fluch der Verdammnis fallen.","type":"dialogue","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Gerecht! sehr gerecht!","type":"dialogue","page":4,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Wie viele Tausende, die voll sich gesoffen haben vom Becher der Wollust, sind durch Leiden gebessert worden! Bedenkt, Vater, wenn Ihr ihn seinem Elend auf einige Zeit preisgeben werdet, wird er nicht entweder umkehren müssen und sich bessern? oder er wird ein Schurke bleiben, und dann – wehe dem Vater, der die Ratschlüsse einer höheren Weisheit durch Verzärtelung zernichtet! – Nun, Vater?","type":"dialogue","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Ich will ihm schreiben, dass ich meine Hand von ihm wende.","type":"dialogue","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Da tut Ihr recht und klug daran.","type":"dialogue","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Dass er nimmer vor meine Augen komme.","type":"dialogue","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Das wird eine heilsame Wirkung tun.","type":"dialogue","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR  (zärtlich)","type":"speaker","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Bis er anders worden!","type":"dialogue","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Schon recht! schon recht.","type":"dialogue","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Halt! noch ein Wort, Vater! Eure Entrüstung, fürchte ich, möchte Euch zu harte Worte in die Feder werfen, die ihm das Herz zerspalten würden – glaubt Ihr nicht, dass er das schon für Verzeihung nehmen werde, wenn Ihr ihn noch eines eigenhändigen Schreibens werthaltet? Darum wird's besser sein, Ihr überlasst das Schreiben mir.","type":"dialogue","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Tu das, mein Sohn. – Ach, es hätte mir doch das Herz gebrochen! Schreib ihm – –","type":"dialogue","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ  (schnell)","type":"speaker","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Dabei bleibt's also?","type":"dialogue","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Schreib ihm, dass ich tausend blutige Tränen, tausend schlaflose Nächte – aber bring meinen Sohn nicht zur Verzweiflung!","type":"dialogue","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Wollt Ihr Euch nicht zu Bette legen, Vater? Es griff Euch hart an.","type":"dialogue","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Schreib ihm, dass die väterliche Brust – Ich sage dir, bring meinen Sohn nicht zur Verzweiflung! (Geht traurig ab.)","type":"dialogue","page":5,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"FRANZ  (mit Lachen ihm nachsehend)","type":"speaker","page":6,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Tröste dich, Alter! du wirst ihn nimmer an diese Brust drücken; der Weg dazu ist verrammelt. Er war aus deinen Armen gerissen, ehe du wusstest, dass du es wollen könntest – (lacht) Da müsst' ich ein erbärmlicher Stümper sein, wenn ich's nicht einmal so weit gebracht hätte, einen Sohn vom Herzen des Vaters loszulösen. Glück zu, Franz! weg ist das Schoßkind – der Wald ist heller. (Er liest die zerrissenen Briefstücke zusammen.)","type":"dialogue","page":6,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Und Gram wird auch den Alten bald fortschaffen, – und ihr muss ich diesen Karl aus dem Herzen reißen, wenn auch ihr halbes Leben dran hängen bleiben sollte.","type":"dialogue","page":6,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Warum bin ich nicht der Erste aus Mutterleib gekrochen? Warum nicht der Einzige? Wirklich, ich glaube, sie hat von allen Menschensorten das Scheußliche auf einen Haufen geworfen und mich daraus gebacken. Mord und Tod!","type":"dialogue","page":6,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Wer hat ihr die Vollmacht gegeben, jenem dieses zu verleihen und mir vorzuenthalten? Warum ging sie so parteilich zu Werke?","type":"dialogue","page":6,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Nein! nein! ich tu' ihr Unrecht. Gab sie uns doch Erfindungsgeist mit, setzte uns nackt und armselig ans Ufer dieses großen Oceans Welt – Schwimme, wer schwimmen kann, und wer zu plump ist, geh unter!","type":"dialogue","page":6,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Sie gab mir nichts mit; wozu ich mich machen will, das ist nun meine Sache. Jeder hat gleiches Recht zum Größten und Kleinsten; Anspruch wird an Anspruch, Trieb an Trieb und Kraft an Kraft zernichtet. Das Recht wohnt beim Überwältiger.","type":"dialogue","page":6,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Also frisch drüber hinweg! Wer nichts fürchtet, ist nicht weniger mächtig als Der, den Alles fürchtet. Wir wollen uns ein Gewissen nach der neuesten Façon anmessen lassen.","type":"dialogue","page":6,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Was können wir dafür? Ich habe Langes und Breites von einer sogenannten Blutliebe schwatzen gehört.– Das ist dein Bruder! – das ist verdolmetscht: er ist aus eben dem Ofen geschossen worden, aus dem du geschossen bist – also sei er dir heilig!","type":"dialogue","page":6,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Aber weiter – es ist dein Vater! er hat dir das Leben gegeben, du bist sein Fleisch, sein Blut – also sei er dir heilig!","type":"dialogue","page":6,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Ich möchte doch fragen, warum hat er mich gemacht? doch wohl nicht gar aus Liebe zu mir, der erst ein Ich werden sollte? Hat er mich gekannt, ehe er mich machte? Oder hat er mich gedacht, wie er mich machte? Oder hat er mich gewünscht, da er mich machte? Wusste er, was ich werden würde? Das wollt' ich ihm nicht raten, sonst möcht' ich ihn dafür strafen, dass er mich doch gemacht hat! Kann ich's ihm Dank wissen, dass ich ein Mann wurde? So wenig, als ich ihn verklagen könnte, wenn er ein Weib aus mir gemacht hätte. Kann ich eine Liebe erkennen. Soll ich ihm etwa darum gute Worte geben, dass er mich liebt? Soll auch ich mich dadurch gängeln lassen?","type":"dialogue","page":6,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"Frisch also! mutig ans Werk! – Ich will Alles um mich her ausrotten, was mich einschränkt, dass ich nicht Herr bin. Herr muss ich sein, dass ich das mit Gewalt ertrotze. (Ab.)","type":"dialogue","page":6,"act":"ERSTER AKT","scene":"1. SZENE"},{"text":"2. SZENE","type":"scene","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Schenke an den Grenzen von Sachsen.","type":"setting","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Karl von Moor in ein Buch vertieft. Spiegelberg trinkend am Tisch.","type":"setting","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"KARL V. MOOR  (legt das Buch weg)","type":"speaker","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Mir ekelt vor diesem tintenklecksenden Säkulum, wenn ich in meinem Plutarch lese von großen Menschen.","type":"dialogue","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG  (stellt ihm ein Glas hin und trinkt)","type":"speaker","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Den Josephus musst du lesen.","type":"dialogue","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Der Lichtfunke Prometheus' ist ausgebrannt. Theaterfeuer, das keine Pfeife Tabak anzündet. Da krabbeln sie nun, studieren sich das Mark aus dem Schädel. Ein französischer Abbé dosiert, Alexander sei ein Hasenfuß gewesen; ein schwindsüchtiger Professor hält sich bei jedem Wort ein Fläschchen Salmiakgeist vor die Nase und liest ein Collegium über die Kraft. Kerls, die in Ohnmacht fallen, wenn sie einen Buben gemacht haben, kritteln über die Taktik des Hannibals.","type":"dialogue","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Das ist recht alexandrinisch geflennt.","type":"dialogue","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Pfui! pfui über das schlappe Kastraten-Jahrhundert.","type":"dialogue","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Zu nichts nütze, als die Taten der Vorzeit wiederzukäuen und die Helden des Altertums mit Kommentationen zu schinden und zu verhunzen mit Trauerspielen. Die Kraft seiner Lenden ist versiegen gegangen, und nun muss Bierhefe den Menschen fortpflanzen helfen.","type":"dialogue","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Tee, Bruder, Tee!","type":"dialogue","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Da verrammeln sie sich die gesunde Natur mit abgeschmackten Konventionen, haben das Herz nicht, ein Glas zu leeren, weil sie Gesundheit dazu trinken müssen – fallen auf die Knie, damit sie ja ihren Schlamp ausbreiten können. Fallen in Ohnmacht, wenn sie eine Gans bluten sehen, und klatschen in die Hände, wenn ihr Nebenbuhler bankrott von der Börse geht – – Hölle und Teufel!","type":"dialogue","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Und um so ein paar tausend lausige Dukaten –","type":"dialogue","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Nein, ich mag nicht daran denken! Ich soll meinen Leib pressen in eine Schnürbrust und meinen Willen schnüren in Gesetze. Das Gesetz hat zum Schneckengang verdorben, was Adlerflug geworden wäre. Das Gesetz hat noch keinen großen Mann gebildet, aber die Freiheit brütet Kolosse und Extremitäten aus. Sie verpalisadieren.","type":"dialogue","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"(Er wirft den Degen auf den Tisch und steht auf.)","type":"direction","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Freiheit!","type":"dialogue","page":7,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG  (aufspringend)","type":"speaker","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Bravo! Bravissimo! Ich will dir was ins Ohr sagen, Moor, das schon lang mit mir umgeht, und du bist der Mann dazu – (sauf, Bruder, sauf!) – wie wär's, wenn wir Juden…","type":"dialogue","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Spiegelberg!","type":"dialogue","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"…würden und das Königreich wieder aufs Tapet brächten!","type":"dialogue","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR  (lacht aus vollem Halse)","type":"speaker","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Sag', ist das nicht ein schlauer und herzhafter Plan? Wir lassen ein Manifest ausgehen in alle vier Enden der Welt und zitieren nach Palästina, was kein Schweinefleisch isst. Das wird ein Victoria abgeben, Kerl, wenn sie…","type":"dialogue","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR  (nimmt ihn lächelnd bei der Hand)","type":"speaker","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Kamerad! mit den Narrenstreichen ist's nun am Ende.","type":"dialogue","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG  (stutzig)","type":"speaker","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Komm, du wirst doch nicht gar den verlorenen Sohn spielen wollen? Kerl, wie du, der mit dem Degen mehr auf die Gesichter gekritzelt hat, als drei Substituten in einem Schaltjahr ins Befehlbuch schreiben! Soll ich dir von der großen Hundsleiche vorerzählen? Ha!","type":"dialogue","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Und du schämst dich nicht, damit groß zu prahlen? Hast nicht einmal so viel Scham, dich dieser Streiche zu schämen?","type":"dialogue","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Geh, geh! Du bist nicht mehr Moor. Weißt du`s noch? Weißt du noch, wie tausendmal du, die Flasche in der Hand, den alten Moor hast aufgezogen und gesagt: er soll nur drauf los schaben und scharren, du wollest dir dafür die Gurgel absaufen? – Weißt du noch? he? weißt du noch? O du heilloser, erbärmlicher Prahlhans! das war noch männlich gesprochen und edelmännisch, aber – Freiheit!","type":"dialogue","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Verflucht seist du, dass du mich dran erinnerst! verflucht ich, dass ich es sagte! Aber es war nur im Dampfe des Weins, und mein Herz hörte nicht, was meine Zunge prahlte.","type":"dialogue","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG  (schüttelt den Kopf)","type":"speaker","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Nein! nein! nein! das kann nicht sein. Unmöglich, Bruder, das kann dein Ernst nicht sein. Sag, Karl, ist es nicht die Not, die dich so stimmt? Komm!","type":"dialogue","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"…dass du sehen sollst, wie die Kräfte wachsen in der Not. Der Mut wächst mit der Gefahr; die Kraft erhebt sich im Drang. Das Schicksal muss einen großen Mann aus mir haben wollen, weil's mir so quer durch den Weg streicht.","type":"dialogue","page":8,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR  (ärgerlich)","type":"speaker","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Ich wüsste nicht, wozu wir den Mut noch haben sollten, und noch nicht gehabt hätten.","type":"dialogue","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"So? – Und du willst also deine Gaben in dir verwittern lassen? Meinst du, deine Stänkereien in Leipzig machen die Grenzen des menschlichen Witzes aus? Da lass uns erst in die große Welt kommen. Paris und London! – wo man Ohrfeigen einhandelt, wenn man Einen mit dem Namen eines ehrlichen Mannes grüßt. Du wirst gaffen! du wirst Augen machen! Wart, und wie man Handschriften nachmacht, Würfel verdreht, Schlösser aufbricht und den Koffern das Eingeweide ausschüttet – das sollst du noch von Spiegelberg lernen!","type":"dialogue","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR  (zerstreut)","type":"speaker","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Wie? Du hast es wohl gar noch weitergebracht?","type":"dialogue","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Wart, lass mich erst warm werden! du sollst Große Gedanken gären in meinem schöpferischen Schädel. Ich erwache, fühle, wer ich bin – wer ich werden muss!","type":"dialogue","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Du bist ein Narr. Der Wein bramarbasiert aus deinem Gehirne.","type":"dialogue","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG  (hitziger)","type":"speaker","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Spiegelberg, wird es heißen, kannst du hexen, Spiegelberg? Es ist schade, dass du kein General worden bist, Spiegelberg.","type":"dialogue","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Glück auf den Weg! Steig du auf Schandsäulen zum Gipfel des Ruhms. Im Schatten meiner väterlichen Haine, in den Armen meiner Amalia lockt mich ein edles Vergnügen. Schon die vorige Woche hab' ich meinem Vater um Vergebung geschrieben, hab' ihm nicht den kleinsten Umstand verschwiegen, und wo Aufrichtigkeit ist, ist auch Mitleid und Hilfe. Lass uns Abschied nehmen, Moritz. Wir sehen uns heut und nie mehr. Die Post ist angelangt. Die Verzeihung meines Vaters ist schon innerhalb dieser Stadtmauern mit der Post angekommen. Ciao! Gute Nacht!","type":"dialogue","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Roller. Schufterle. Razmann treten auf.","type":"direction","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"ROLLER","type":"speaker","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Wisst ihr auch, dass man uns auskundschaftet?","type":"dialogue","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"RAZMANN","type":"speaker","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Dass wir keinen Augenblick sicher sind, aufgehoben zu werden?","type":"dialogue","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Saht ihr den Schweizer nicht? sagt' er euch von keinem Brief, den er an mich hätte?","type":"dialogue","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"ROLLER","type":"speaker","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Schon lang sucht er dich, ich vermute so etwas.","type":"dialogue","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Wo ist er? wo, wo? (Will eilig fort.)","type":"dialogue","page":9,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"ROLLER","type":"speaker","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Bleib! wir haben ihn hierher beschieden.","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Schweizer auf mit einem Brief, den er Karl gibt.","type":"direction","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"ROLLER","type":"speaker","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Du zitterst? –","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Ich zittere nicht. Warum sollte ich auch zittern? Kameraden! dieser Brief – Freut euch mit mir! Ich bin der Glücklichste unter der Sonne, warum sollt' ich zittern?","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SCHUFTERLE","type":"speaker","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Was ist dir? wirst du nicht wie die Wand?","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"RAZMANN","type":"speaker","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Du zitterst.","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Meines Bruders Hand!","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Moor lässt den Brief fallen und rennt hinaus. Alle fahren auf.","type":"direction","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"ROLLER  (ihm nach)","type":"speaker","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Moor! wo hinaus, Moor? was beginnst du?","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"RAZMANN","type":"speaker","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Was hat er? was hat er? Er ist bleich wie die Leiche.","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Das müssen schöne Neuigkeiten sein! Lass doch sehen!","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"(nimmt den Brief von der Erde und liest).","type":"direction","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"»Unglücklicher Bruder!« der Anfang klingt lustig. »Nur kürzlich muss ich dir melden, dass deine Hoffnung vereitelt ist. – du sollst hingehen, lässt dir der Vater sagen, wohin dich deine Schandtaten führen.","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Schweizer nimmt den Brief weg, liest weiter.","type":"direction","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Auch, sagt er, werdest du dir keine Hoffnung machen, jemals Gnade zu seinen Füßen zu erwimmern, wenn du nicht gewärtig sein wollest, im untersten Gewölbe seiner Türme mit Wasser und Brot so lang traktiert zu","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"werden, bis deine Haare wachsen wie Adlers Federn, und deine Nägel wie","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Vogelklauen werden. Das sind seine eigenen Worte. Er befiehlt mir, den Brief zu schließen. Leb wohl auf ewig! Ich bedaure dich –","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Franz von Moor.«","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Ein zuckersüßes Brüderchen!","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"RAZMANN","type":"speaker","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"In der Tat! – Franz heißt die Canaille?","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG  (sachte herbeischleichend)","type":"speaker","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Von Wasser und Brot ist die Rede? Ein schönes Leben! Da hab' ich anders für euch gesorgt! Sagt' ich's nicht, ich müsste am Ende für euch alle denken?","type":"dialogue","page":10,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Was sagt der Schafskopf? der Esel will für uns alle denken?","type":"dialogue","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Hasen, Krüppel, lahme Hunde seid ihr Alle, wenn ihr das Herz nicht habt, etwas Großes zu wagen!","type":"dialogue","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"ROLLER","type":"speaker","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Nun, das wären wir, du hast recht! – aber wird es uns auch aus dieser vermaledeiten Lage reißen, was du wagen wirst? wird es? –","type":"dialogue","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG  (mit einem stolzen Gelächter)","type":"speaker","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Armer Tropf! aus dieser Lage reißen? hahaha! – aus dieser Lage reißen? – und auf mehr raffiniert dein Fingerhut voll Gehirn nicht? und damit trabt deine Mähre zum Stalle? Spiegelberg müsste ein Hundsfott sein, wenn er mit dem nur anfangen wollte. Zu Helden, sag ich dir, zu Freiherrn, zu Fürsten, zu Göttern wird's euch machen!","type":"dialogue","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"RAZMANN","type":"speaker","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Das ist viel auf einen Hieb, wahrlich! Aber es wird wohl eine halsbrechende Arbeit sein! den Kopf wird's wenigstens kosten.","type":"dialogue","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Es will nichts als Mut, denn was den Witz betrifft, den nehme ich gern über mich.","type":"dialogue","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Mut sag' ich, Schweizer!","type":"dialogue","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Mut, Roller, Razmann, Schufterle!","type":"dialogue","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Mut! –","type":"dialogue","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Mut? Wenn's nur das ist – Mut hab' ich genug, um barfuß mitten durch die Hölle zu gehn.","type":"dialogue","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SCHUFTERLE","type":"speaker","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Mut genug, mich unterm lichten Galgen mit dem leibhaftigen Teufel, um einen armen Sünder zu balgen.","type":"dialogue","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"So gefällt mir's! Wenn ihr Mut habt, trete Einer auf und sag': er habe noch etwas zu verlieren, und nicht Alles zu gewinnen!","type":"dialogue","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"RAZMANN","type":"speaker","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Wahrhaftig, da gäb's Manches zu verlieren, wenn ich Das verlieren wollte, was ich noch zu gewinnen habe!","type":"dialogue","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"ROLLER","type":"speaker","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Ja, zum Teufel! und Manches zu gewinnen, wenn ich Das gewinnen wollte, was ich nicht verlieren kann.","type":"dialogue","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SCHUFTERLE","type":"speaker","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Wenn ich Das verlieren müsste, was ich auf Borg auf dem Leibe trage, so hätt' ich allenfalls morgen nichts mehr zu verlieren.","type":"dialogue","page":11,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Also denn! (Er stellt sich mitten unter sie mit beschwörendem Ton.) Wenn noch ein Tropfen deutschen Heldenbluts in euren Adern rinnt – kommt! Wir wollen uns in den böhmischen Wäldern niederlassen, dort eine Räuberbande zusammenziehen und – Was gafft ihr mich an? – ist euer bisschen Mut schon verdampft?","type":"dialogue","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"RAZMANN","type":"speaker","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Du bist wohl nicht der erste Gauner, der über den hohen Galgen weggesehen hat – und doch – Was hätten wir sonst noch für eine Wahl übrig?","type":"dialogue","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Wahl? Was? Nichts habt ihr zu wählen! Wollt ihr im Schuldturm stecken und zusammenschnurren, bis man zum jüngsten Tag posaunt? Wollt ihr ein mageres Almosen erpressen?","type":"dialogue","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"ROLLER","type":"speaker","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"So unrecht hat der Spiegelberg eben nicht. Ich habe auch meine Plane schon zusammen gemacht. Wie wär's, dachte ich, wenn ihr euch hinsetztet und ein Taschenbuch, oder einen Almanach zusammensudeltet und um den lieben Groschen rezensiertet?","type":"dialogue","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Zum Henker! Ihr ratet nah zu meinen Projekten. Ich dachte bei mir selbst, wenn du Anhänger der Frömmigkeit und Nächstenliebe würdest und wöchentlich deine Erbauungsstunden hieltest?","type":"dialogue","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"RAZMANN","type":"speaker","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Oder zögen wir wider die Franzosen zu Felde –","type":"dialogue","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER  (steht auf und gibt Spiegelberg die Hand.)","type":"speaker","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Moritz, du bist ein großer Mann! – oder es hat ein blindes Schwein eine Eichel gefunden.","type":"dialogue","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"RAZMANN","type":"speaker","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Vortrefflicher Plan! Du bist ein Meisterredner, Spiegelberg, wenn's drauf ankommt, aus einem ehrlichen Mann einen Hallunken zu machen-","type":"dialogue","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER  (klopft ihn auf die Achsel)","type":"speaker","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Meisterlich, Spiegelberg! meisterlich! Was, zum Teufel, steht ihr da und zaudert?","type":"dialogue","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"ROLLER","type":"speaker","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Du auch Schweizer? Also verpfänd‘ ich dem Teufel meine Seele.","type":"dialogue","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SCHUFTERLE","type":"speaker","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Kommt, Kameraden!","type":"dialogue","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Sachte nur! sachte! Wohin? Das Tier muss auch seinen Kopf haben, Kinder!","type":"dialogue","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG  (giftig)","type":"speaker","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Was predigt der Zauderer? Stand nicht der Kopf schon, eh noch ein Glied sich regte? Folgt, Kameraden!","type":"dialogue","page":12,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Auch die Freiheit muss ihren Herrn haben.","type":"dialogue","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG  (geschmeidig)","type":"speaker","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Schweizer sagt recht. Und das muss ein erleuchteter Kopf sein. Versteht ihr? Ein feiner, politischer Kopf muss das sein. Ja, wenn ich mir's denke, was ihr vor einer Stunde wart, was ihr jetzt seid, – durch einen glücklichen Gedanken seid – Ja, freilich, freilich müsst ihr einen Chef haben – Und wer diesen Gedanken entsponnen, sagt, muss das nicht ein erleuchteter politischer Kopf sein?","type":"dialogue","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"ROLLER","type":"speaker","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Wenn sich's hoffen ließe – träumen ließe – Aber ich fürchte, er wird es nicht tun.","type":"dialogue","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Sag's keck heraus, Freund, vielleicht wird er's doch tun.","type":"dialogue","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Ohne den Moor sind wir Leib ohne Seele.","type":"dialogue","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG  (unwillig von ihm weg)","type":"speaker","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Stockfisch!","type":"dialogue","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR  (tritt herein in wilder Bewegung und läuft heftig im Zimmer auf und nieder, mit sich selbst.)","type":"speaker","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Menschen – Menschen! falsche, heuchlerische Krokodilbrut! Ihre Augen sind Wasser! ihre Herzen sind Erz! Küsse auf den Lippen! Und Er, Er – Bosheit hab' ich dulden gelernt, kann dazu lächeln, wenn mein erboster Feind mir","type":"dialogue","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"mein eigenes Herzblut zutrinkt – aber wenn Blutliebe zur Verräterin, wenn Vaterliebe zur Furie wird: und so fange Feuer, männliche Gelassenheit!","type":"dialogue","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"ROLLER","type":"speaker","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Höre Moor, was denkst du? Ein Räuberleben ist doch besser als bei Wasser und Brot im Turm","type":"dialogue","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Ist das Vatertreue? Ist das Liebe für Liebe? Reue und keine Gnade! Oh, ich möchte den Ozean vergiften, dass sie den Tod aus allen Quellen saufen! Und kein Erbarmen!","type":"dialogue","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"ROLLER","type":"speaker","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"So höre doch, Moor, was ich dir sage!","type":"dialogue","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Es ist unglaublich, es ist ein Traum, eine Täuschung –","type":"dialogue","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"RAZMANN","type":"speaker","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Höre doch, höre! vor Rasen hörst du ja nicht.","type":"dialogue","page":13,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Weg, weg von mir! Ist dein Name nicht Mensch! Hat dich das Weib nicht geboren? – Aus meinen Augen, du mit dem Menschengesicht! – Ich habe ihn so unaussprechlich geliebt! so liebte kein Sohn; ich hätte tausend Leben für ihn – (Schäumend auf die Erde stampfend.) Ha! – wer mir jetzt ein Schwert in die Hand gäbe, dieser Otterbrut, wer mir sagte, wo ich das Herz ihres Lebens erziele. Er sei mein Freund, mein Engel, mein Gott – ich will ihn anbeten!","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"RÄUBER  (durcheinander)","type":"speaker","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Moor!","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Moor!","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Moor!","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"ROLLER","type":"speaker","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Wir wollen eine Räuberbande sammeln, und du – (Moor stiert ihn an.)","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"RAZMANN","type":"speaker","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Du sollst unser Hauptmann sein!","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Du musst unser Hauptmann sein!","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG  (wirft sich wild in einen Sessel)","type":"speaker","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Sklaven und Memmen!","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Wer blies dir das Wort ein? Das hast du nicht aus deiner Menschenseele hervorgeholt! Wer blies dir das Wort ein? Ja, bei dem tausendarmigen Tod!","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"das wollen wir! das müssen wir! Der Gedanke verdient Vergötterung – Räuber und Mörder! – So wahr meine Seele lebt, ich bin euer Hauptmann!","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"ALLE  (mit lärmendem Geschrei)","type":"speaker","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Es lebe der Hauptmann!","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG  (aufspringend, vor sich)","type":"speaker","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Bis ich ihm hin helfe!","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Was für ein Tor ich war, dass ich in den Käfig zurückwollte! – Mein Geist dürstet nach Taten, mein Atem nach Freiheit. – Mörder, Räuber! – Ich habe keinen Vater mehr, ich habe keine Liebe mehr, und Blut und Tod soll mich vergessen lehren, dass mir jemals etwas teuer war! – Ich bin euer Hauptmann!","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Karl!","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Schwört mir Treue und Gehorsam zu bis in den Tod!","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Karl!","type":"dialogue","page":14,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"ALLE  (geben ihm die Hand)","type":"speaker","page":15,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Wir schwören dir Treu und Gehorsam bis in den Tod!","type":"dialogue","page":15,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":15,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Ich schwör' euch hier, treu und standhaft euer Hauptmann zu bleiben bis in den Tod! Den soll dieser Arm gleich zur Leiche machen, der jemals zagt oder zweifelt, oder zurücktritt! Ein Gleiches widerfahre mir von Jedem unter euch, wenn ich meinen Schwur verletze!","type":"dialogue","page":15,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"(Spiegelberg läuft wütend auf und nieder.)","type":"direction","page":15,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Amalia und der alte Moor schauen sich Bilder an. Amalia: das ist nicht Karl. Nein, nein, er ist`s nicht.","type":"direction","page":15,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":15,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Nun denn, so lasst uns gehn! Fürchtet euch nicht vor Tod und Gefahr. Im Gewühl des Gefechts, oder auf offenem Galgen und Rad! Eins davon ist unser Schicksal! (Sie gehen ab.)","type":"dialogue","page":15,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"SPIEGELBERG  (ihnen nachsehend, nach einer Pause)","type":"speaker","page":15,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"Dein Register hat ein Loch. Du hast das Gift weggelassen. (Ab.)","type":"dialogue","page":15,"act":"ERSTER AKT","scene":"2. SZENE"},{"text":"3. SZENE","type":"scene","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Im Moorischen Schloss. Amalias Zimmer.","type":"setting","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Amalia. Franz.","type":"setting","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"FRANZ","type":"speaker","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Du siehst weg, Amalia? Verdien' ich weniger als Der, den der Vater verflucht hat?","type":"dialogue","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"AMALIA","type":"speaker","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Weg! – Ha des liebevollen, barmherzigen Vaters, der seinen Sohn Wölfen und Ungeheuern preisgibt! Daheim labt er sich mit süßem köstlichem Wein und pflegt seiner morschen Glieder in Kissen von Eider, während sein großer, herrlicher Sohn darbt – Schämt euch, ihr Unmenschen! schämt euch, ihr Drachenseelen, ihr Schande der Menschheit! – seinen einzigen Sohn!","type":"dialogue","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"FRANZ","type":"speaker","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Ich dächte, er hätt' ihrer zwei.","type":"dialogue","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"AMALIA","type":"speaker","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Ja, er verdient solche Söhne zu haben, wie du bist. Auf seinem Todbett wird er umsonst die welken Hände ausstrecken nach seinem Karl und schaudernd zurückfahren, wenn er die eiskalte Hand seines Franzens fasst. – Oh es ist süß, es ist köstlich süß, von deinem Vater verflucht zu werden! Sprich, Franz, liebe brüderliche Seele, was muss man tun, wenn man von ihm verflucht sein will?","type":"dialogue","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"FRANZ","type":"speaker","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Du schwärmst, meine Liebe, du bist zu bedauern.","type":"dialogue","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"AMALIA","type":"speaker","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"O ich bitte dich – bedauerst du deinen Bruder? – Nein, Unmensch, du hassest ihn! Du hassest mich doch auch?","type":"dialogue","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"FRANZ","type":"speaker","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Ich liebe dich, wie mich selbst, Amalia!","type":"dialogue","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"AMALIA","type":"speaker","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Wenn du mich liebst, kannst du mir wohl eine Bitte abschlagen?","type":"dialogue","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"FRANZ","type":"speaker","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Keine, keine, wenn sie nicht mehr ist als mein Leben.","type":"dialogue","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"AMALIA","type":"speaker","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"O, wenn das ist! Eine Bitte, die du so leicht, so gern erfüllen wirst – (stolz) Hasse mich! Ich müsste feuerrot werden vor Scham, wenn ich an Karln denke und mir eben einfiel', dass du mich nicht hassest. Du versprichst mir's doch? – Jetzt geh und lass mich, ich bin so gern allein!","type":"dialogue","page":16,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"FRANZ","type":"speaker","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Allerliebste Träumerin! Hattest du ihm nicht einen Ring an den Finger gesteckt? einen Diamantring, zum Unterpfand deiner Treu! – Freilich nun, wie kann auch ein Jüngling den Reizen einer Metze Widerstand tun? Wer wird's ihm auch verdenken, da ihm sonst nichts mehr übrig war wegzugeben – und bezahlte sie ihn nicht mit Wucher dafür mit ihren Liebkosungen, ihren Umarmungen?","type":"dialogue","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"AMALIA  (aufgebracht)","type":"speaker","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Meinen Ring einer Metze?","type":"dialogue","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"FRANZ","type":"speaker","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Keinen andern, Amalia – ha! solch ein Kleinod, und an meinem Finger – und von Amalia! – von hier sollt’ ihn der Tod nicht gerissen haben – nicht wahr, Amalia, nicht die Kostbarkeit des Diamants, nicht die Kunst des Gepräges – die Liebe macht seinen Wert aus. – Liebstes Kind, du weinest? wehe über den, der diese köstliche Tropfen aus so himmlischen Augen presst!","type":"dialogue","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"AMALIA  (schlägt ihn)","type":"speaker","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Schamloser Lästerer! Wohin so eilig, fliehst du vor deiner eigenen Schande?","type":"dialogue","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"FRANZ","type":"speaker","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Lass mich, lass mich! – meinen Tränen den Lauf lassen tyrannischer Vater! den besten deiner Söhne so hinzugeben dem Elend – der rings umgebenden Schande – lass mich, Amalia! ich will ihm zu Füßen fallen, auf den Knien will ich ihn beschwören, den ausgesprochenen Fluch auf mich, auf mich zu laden – mich zu enterben – mich – mein Blut – mein Leben – alles –","type":"dialogue","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"AMALIA","type":"speaker","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Bruder meines Karls, bester, liebster Franz!","type":"dialogue","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"FRANZ","type":"speaker","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"O Amalia! Wie lieb ich dich um dieser unerschütterten Treue gegen meinen Bruder – verzeih, dass ich es wagte, deine Liebe auf diese harte Probe zu setzen! – Wie schön hast du meine Wünsche gerechtfertigt! – mit diesen Tränen, diesen Seufzern, diesem himmlischen Unwillen – auch für mich, für mich – unsere Seelen stimmten so zusammen.","type":"dialogue","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"AMALIA","type":"speaker","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"O nein, das taten sie nie!","type":"dialogue","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"FRANZ","type":"speaker","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Es war ein stiller heiterer Abend, der letzte, eh er nach Leipzig abreiste, da er mich mit sich in jene Laube nahm, – stumm blieben wir lang – zuletzt sprach er leise mit Tränen: Ich verlasse Amalia, - verlass sie nicht, Bruder! – sei ihr Freund – ihr Karl – wenn Karl – nimmer – wiederkehrt – Nimmer, nimmer, nimmer wird er wiederkehren, und ich hab’s ihm zugesagt mit einem heiligen Eide!","type":"dialogue","page":17,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"AMALIA  (zurückspringend)","type":"speaker","page":18,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Verräter, wie ich dich ertappe! In eben dieser Laube beschwur er mich, keiner andern Liebe – siehst du, wie gottlos, wie abscheulich du – geh aus meinen Augen!","type":"dialogue","page":18,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"FRANZ","type":"speaker","page":18,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Du hassest mich.","type":"dialogue","page":18,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"AMALIA","type":"speaker","page":18,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Ich verachte dich, geh!","type":"dialogue","page":18,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"FRANZ  (mit den Füßen stampfend)","type":"speaker","page":18,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Wart! so sollst du vor mir zittern! (ab).","type":"dialogue","page":18,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"AMALIA","type":"speaker","page":18,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"Geh! – Bettler sind Könige, und Könige sind Bettler! – Ich möchte die Lumpen, die er anhat, nicht mit dem Purpur der Gesalbten vertauschen. Der Blick, mit dem er bettelt, das muss ein großer, ein königlicher Blick sein. Jetzt bin ich wieder bei Karln – In den Staub mit dir, du prangendes Geschmeide! (Sie reißt sich die Perlen vom Hals.) Karl! Karl! so bin ich dein wert – (Ab.)","type":"dialogue","page":18,"act":"ERSTER AKT","scene":"3. SZENE"},{"text":"ZWEITER AKT","type":"act","page":19,"act":"ZWEITER AKT","scene":null},{"text":"1. SZENE","type":"scene","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ VON MOOR  (nachdenkend in seinem Zimmer)","type":"speaker","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Es dauert mir zu lange – das Leben eines Alten ist doch eine Ewigkeit!","type":"dialogue","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Ein Licht ausgeblasen, das ohnehin nur mit den letzten Öltropfen noch wuchert – mehr ist’s nicht – Und doch möcht ich das nicht gern selbst getan haben um der Leute willen. Ich möchte ihn nicht gern getötet, aber abgelebt.","type":"dialogue","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Und wie ich nun werde zu Werk gehen müssen?","type":"dialogue","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Welche Gattung von Empfindnissen ich werde wählen müssen?","type":"dialogue","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Zorn? – Sorge? – Gram? – Furcht?","type":"dialogue","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Wie? – Nun? – Was? Nein! – Ha! (Auffahrend.) Schreck! – Was kann der Schreck nicht? – Was kann Vernunft, Religion wider dieses Giganten eiskalte Umarmung? – Und doch? – Wenn er auch diesem Sturm stünde? – Wenn er? – O so komme zu mir zu Hülfe Jammer, und du Reue, höllische Eumenide, grabende Schlange, die ihren Fraß wiederkäut und ihren eigenen Kot wiederfrisst; ewige Zerstörerinnen und ewige Schöpferinnen eures Giftes, und du, heulende Selbstverklagung, die du dein eigen Haus verwüstest, und deine eigene Mutter verwundest – Und kommt auch ihr mir zu Hülfe wohltätige Grazien selbst, sanft lächelnde Vergangenheit, und du mit dem überquellenden Füllhorn, blühende Zukunft, haltet ihm in euren Spiegeln die Freuden des Himmels vor, wenn euer fliehender Fuß seinen geizigen Armen entgleitet – So fall ich Streich auf Streich, Sturm auf Sturm dieses zerbrechliche Leben an, bis den Furientrupp zuletzt schließt – die Verzweiflung! Triumph! Triumph! – Der Plan ist fertig – schwer und kunstvoll, wie keiner – zuverlässig – sicher – keine Spuren von Wunde oder Gift. (Entschlossen.) Wohlan denn!","type":"dialogue","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Hermann tritt auf.","type":"direction","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Ha! Deus ex machina! Hermann!","type":"dialogue","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Zu Euren Diensten, gnädiger Junker!","type":"dialogue","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ  (gibt ihm die Hand)","type":"speaker","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Die du keinem Undankbaren erweisest.","type":"dialogue","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Ich hab Proben davon.","type":"dialogue","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Du sollst mehr haben mit nächstem – mit nächstem, Hermann! – Ich habe dir etwas zu sagen, Hermann.","type":"dialogue","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Ich höre mit tausend Ohren.","type":"dialogue","page":19,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Ich kenne dich, du bist ein entschlossener Kerl – Soldatenherz – Haar auf der Zunge! – Mein Vater hat dich sehr beleidigt, Hermann!","type":"dialogue","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Der Teufel hole mich, wenn ich’s vergesse!","type":"dialogue","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Das ist der Ton eines Manns! Rache geziemt einer männlichen Brust. Du gefällst mir, Hermann. Nimm diesen Beutel, Hermann. Er sollte schwerer sein, wenn ich erst Herr wäre.","type":"dialogue","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Das ist ja mein ewiger Wunsch, gnädiger Junker, ich dank Euch.","type":"dialogue","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Wirklich, Hermann? wünschest du wirklich, ich wäre Herr? – aber mein Vater hat das Mark eines Löwen, und ich bin der jüngere Sohn.","type":"dialogue","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Ich wollt’, Ihr wärt der ältere Sohn und Euer Vater hätte das Mark eines schwindsüchtigen Mädchens.","type":"dialogue","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Ha! wie dich der ältere Sohn dann belohnen wollte! wie er dich aus diesem unedlen Staub, der sich so wenig mit deinem Geist und Adel verträgt, ans Licht emporheben wollte! – Dann solltest du, ganz wie du da bist, mit Gold überzogen werden, und mit vier Pferden durch die Straßen dahinrasseln, wahrhaftig, das solltest du! – aber ich vergesse, wovon ich dir sagen wollte – hast du das Fräulein von Edelreich schon vergessen, Hermann?","type":"dialogue","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Wetter Element! was erinnert Ihr mich an das.","type":"dialogue","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Mein Bruder hat sie dir weggefischt.","type":"dialogue","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Er soll dafür büßen!","type":"dialogue","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Sie gab dir einen Korb. Ich glaube gar, er warf dich die Treppen hinunter.","type":"dialogue","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Ich will ihn dafür in die Hölle stoßen.","type":"dialogue","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Nicht so stürmisch, Hermann! Komm näher – du sollst Amalia haben!","type":"dialogue","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Das muss ich, trutz dem Teufel! das muss ich!","type":"dialogue","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Du sollst sie haben, sag ich dir, und das von meiner Hand. Komm näher, sag ich – du weißt vielleicht nicht, dass Karl so gut als enterbt ist?","type":"dialogue","page":20,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN  (näherkommend)","type":"speaker","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Unbegreiflich, das erste Wort, das ich höre.","type":"dialogue","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Sei ruhig, und höre weiter! du sollst ein andermal mehr davon hören – ja, ich sage dir, seit elf Monaten so gut als verbannt. Aber schon bereut der Alte den voreiligen Schritt, den er doch, (lachend) will ich hoffen, nicht selbst getan hat. Auch liegt ihm die Edelreich täglich hart an mit ihren Vorwürfen und Klagen. Über kurz oder lang wird er ihn in allen vier Enden der Welt aufsuchen lassen, und gute Nacht, Hermann! wenn er ihn findet. Du kannst ihm ganz demütig die Kutsche halten, wenn er mit ihr in die Kirche zur Trauung fährt.","type":"dialogue","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Ich will ihn am Kruzifix erwürgen!","type":"dialogue","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Der Vater wird ihm bald die Herrschaft abtreten, und in Ruhe auf seinen Schlössern leben. Jetzt hat der stolze Strudelkopf den Zügel in Händen. Jetzt lacht er seiner Hasser und Neider – und ich, der ich dich zu einem wichtigen großen Manne machen wollte, ich selbst, Hermann, werde tiefgebückt vor seiner Türschwelle –","type":"dialogue","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN  (in Hitze)","type":"speaker","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Nein, so wahr ich Hermann heiße, das sollt Ihr nicht, wenn noch ein Fünkchen Verstand in diese Gehirne glostet! das sollt Ihr nicht!","type":"dialogue","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Wirst du es hindern? auch dich, mein lieber Hermann, wird er seine Geißel fühlen lassen, wird dir ins Angesicht speien, wenn du ihm auf der Straße begegnest, und wehe dir dann, wenn du die Achsel zuckst oder das Maul krümmst – siehe, so steht’s mit deiner Anwerbung ums Fräulein, mit deinen Aussichten, mit deinen Entwürfen.","type":"dialogue","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Sagt mir! was soll ich tun?","type":"dialogue","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Höre dann, Hermann! Dass du siehst, wie ich mir dein Schicksal zu Herzen nehme als ein redlicher Freund – geh – kleide dich um – mach dich ganz unkenntlich, lass dich beim Alten melden, gib vor, du kämest geraden Wegs aus Böhmen, hättest mit meinem Bruder dem Treffen bei Prag beigewohnt – hättest ihn auf der Walstatt den Geist aufgeben sehen –","type":"dialogue","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Wird man mir glauben?","type":"dialogue","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Hoho! dafür lass mich sorgen! Nimm dies, mach jetzt nur, dass du fortkommst, und ungesehen! spring durch die Hintertüre in den Hof, von da über die Gartenmauer – die Katastrophe dieser Tragikomödie überlass mir!","type":"dialogue","page":21,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":22,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Und die wird sein: Vivat der neue Herr, Franziskus von Moor!","type":"dialogue","page":22,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ  (streichelt ihm die Backen)","type":"speaker","page":22,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Wie schlau du bist! – denn siehst du, auf diese Art erreichen wir alle Zwecke zumal und bald. Amalia gibt ihre Hoffnung auf ihn auf. Der Alte misst sich den Tod seines Sohnes bei, und – er kränkelt – ein schwankendes Gebäude braucht des Erdbebens nicht, um übern Haufen zu fallen – er wird die Nachricht nicht überleben – dann bin ich sein einiger Sohn – Amalia hat ihre Stützen verloren, und ist ein Spiel meines Willens, da kannst du leicht denken – kurz, alles geht nach Wunsch – aber du musst dein Wort nicht zurücknehmen!","type":"dialogue","page":22,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":22,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Was sagt Ihr? (Frohlockend.) Eh soll die Kugel in ihrem Lauf zurückkehren- rechnet auf mich! Lasst nur mich machen – Adieu!","type":"dialogue","page":22,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"FRANZ  (ihm nachrufend)","type":"speaker","page":22,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"Die Ernte ist dein, lieber Hermann! – Wenn der Ochse den Kornwagen in die Scheune gezogen hat, so muss er mit Heu vorliebnehmen. Dir eine Stallmagd, und keine Amalia! (Geht ab.)","type":"dialogue","page":22,"act":"ZWEITER AKT","scene":"1. SZENE"},{"text":"2. SZENE","type":"scene","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Des alten Moors Schlafzimmer.","type":"setting","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Der alte Moor schlafend in seinem Lehnsessel. Amalia.","type":"setting","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA  (sachte herbeischleichend)","type":"speaker","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Leise, leise! er schlummert. (Sie stellt sich vor den Schlafenden.)","type":"dialogue","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR  (träumend)","type":"speaker","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Mein Sohn! mein Sohn! mein Sohn!","type":"dialogue","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA  (ergreift seine Hand)","type":"speaker","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Horch, horch! sein Sohn ist in seinen Träumen.","type":"dialogue","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"FRANZ  (hinter der Bühne)","type":"speaker","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Und ich dachte er hätte zwei.","type":"dialogue","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Mein Sohn! Bist du da? bist du wirklich? Ach, wie siehst du so elend! Sieh mich nicht an mit diesem kummervollen Blick! ich bin elend genug.","type":"dialogue","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA  (weckt ihn schnell)","type":"speaker","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Wie schön, wie ehrwürdig! nein, ich kann ihm nicht zürnen.","type":"dialogue","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Lieber Greis! Ihr träumtet nur. Fasst Euch!","type":"dialogue","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR  (halb wach)","type":"speaker","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Er war nicht da? Drückt' ich nicht seine Hände? Garstiger Franz! willst du ihn auch meinen Träumen entreißen?","type":"dialogue","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"(ermuntert sich).","type":"direction","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Wo ist er? wo? wo bin ich? Du da, Amalia?","type":"dialogue","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Wie ist Euch? Ihr schlieft einen erquickenden Schlummer.","type":"dialogue","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Mir träumte von meinem Sohn Karl. Warum hab' ich nicht fortgeträumt? Vielleicht hätte ich Verzeihung erhalten aus seinem Munde.","type":"dialogue","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Engel grollen nicht – er verzeiht Euch. (Fasst seine Hand mit Wehmut.) Vater meines Karls! ich verzeih' Euch.","type":"dialogue","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Kennst du dieses Bild, meine Tochter?","type":"dialogue","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Karls! –","type":"dialogue","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Jetzt ist er anders – Oh, es wütet in meinem Innern – diese Milde ist Unwillen, dieses Lächeln Verzweiflung – Nicht wahr, Amalia? Es war an seinem Geburtstage in der Jasminlaube, als du ihn maltest? – Oh meine Tochter! Eure Liebe machte mich so glücklich.","type":"dialogue","page":23,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA  (immer das Auge auf das Bild geheftet)","type":"speaker","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Nein! nein! er ist's nicht. Bei Gott! Das ist Karl nicht. Weg damit! dies ist so menschlich! Ich war eine Stümperin.","type":"dialogue","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Dieser huldreiche, erwärmende Blick – wär' er vor meinem Bette gestanden, ich hätte gelebt mitten im Tode! Nie, nie wär' ich gestorben!","type":"dialogue","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Nie, nie wärt Ihr gestorben! Dieser Blick hätt' Euch über die Sterne getragen.","type":"dialogue","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Es ist schwer, es ist traurig! Ich sterbe, und mein Sohn Karl ist nicht hier – ich werde zu Grabe getragen, und er weint nicht an meinem Grabe – Wie süß ist's, eingewiegt zu werden in den Schlaf des Todes von dem Gebet eines Sohnes – das ist Wiegengesang.","type":"dialogue","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA  (schwärmend)","type":"speaker","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Ja süß, himmlisch süß ist's, eingewiegt zu werden in den Schlaf des Todes von dem Gesang des Geliebten.","type":"dialogue","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Ein schönes Lied, meine Tochter. Das musst du mir vorspielen, eh ich sterbe.","type":"dialogue","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Karl und ich haben's oft zusammen zu der Laute gesungen. (Spielt fort.)","type":"dialogue","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Daniel tritt auf.","type":"direction","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"DANIEL","type":"speaker","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Es wartet draußen ein Mann auf Euch. Er bittet, vorgelassen zu werden, er hab' Euch eine wichtige Zeitung.","type":"dialogue","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Franz. Hermann verkappt.","type":"direction","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"HERMANN  (mit veränderter Stimme)","type":"speaker","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Gnädiger Herr! lasst es einen armen Mann nicht entgelten, wenn er wider Willen Euer Herz durchbohrt. Ich bin ein Fremdling in diesem Lande, aber Euch kenn' ich sehr gut, Ihr seid der Vater Karls von Moor.","type":"dialogue","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Woher weißt du das?","type":"dialogue","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"HERMANN","type":"speaker","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Ich kannte Euren Sohn –","type":"dialogue","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA  (auffahrend)","type":"speaker","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Er lebt? lebt? Du kennst ihn? wo ist er? wo, wo? (Will hinwegrennen.)","type":"dialogue","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Du weißt von meinem Sohn?","type":"dialogue","page":24,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"HERMANN","type":"speaker","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Er studierte in Leipzig. Von da zog er, ich weiß nicht wie weit, barfuß, und erbettelte sein Brot vor den Türen. Fünf Monate drauf brach der leidige Krieg zwischen Preußen und Österreich wieder aus, und da er auf der Welt nichts mehr zu hoffen hatte, zog ihn der Hall von Friedrichs siegreicher Trommel nach Böhmen. Erlaubt mir, sagte er zum großen Schwerin, dass ich den Tod sterbe auf dem Bette der Helden, ich hab' keinen Vater mehr! –","type":"dialogue","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Sieh mich nicht an, Amalia!","type":"dialogue","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"HERMANN","type":"speaker","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Ich traf ihn am Abend der Schlacht niedergesunken unter Kugelgepfeife, mit der Linken hielt er das stürzende Blut, die Rechte hatte er in die Erde gegraben. Bruder! rief er mir entgegen, nun, wer ein braver Soldat ist, rief er und ließ die linke Hand los, der folge seinem General wie ich! Bald darauf hauchte er seine große Seele dem Helden zu.","type":"dialogue","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"FRANZ  (wild auf Hermann losgehend)","type":"speaker","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Dass der Tod deine verfluchte Zunge versiegle! Bist du hierhergekommen, unserem Vater den Todesstoß zu geben? – Vater! Amalia! Vater!","type":"dialogue","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"HERMANN","type":"speaker","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Es war der letzte Wille meines sterbenden Kameraden. Nimm dies Schwert, röchelte er, du wirst es meinem alten Vater überliefern; das Blut seines Sohnes klebt daran. Sag' ihm, sein Fluch hätte mich gejagt in Kampf und Tod, ich sei gefallen in Verzweiflung! Sein letzter Seufzer war Amalia.","type":"dialogue","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA  (wie aus einem Todesschlummer aufgejagt)","type":"speaker","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Sein letzter Seufzer Amalia.","type":"dialogue","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR  (grässlich schreiend, sich die Haare ausraufend)","type":"speaker","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Mein Fluch ihn gejagt in den Tod! gefallen in Verzweiflung!","type":"dialogue","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"FRANZ  (umherirrend im Zimmer)","type":"speaker","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Oh! was habt Ihr gemacht, Vater? Mein Karl, mein Bruder!","type":"dialogue","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"HERMANN","type":"speaker","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Hier ist das Schwert, und hier ist auch ein Portrait, das er zu gleicher Zeit aus dem Busen zog! Es gleicht diesem Fräulein auf ein Haar. Dies soll meinem Bruder Franz, sagte er, – ich weiß nicht, was er damit sagen wollte.","type":"dialogue","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"FRANZ  (wie erstaunt)","type":"speaker","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Mir? Amalias Portrait? Mir, Karl, Amalia? Mir?","type":"dialogue","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA  (heftig auf Hermann losgehend)","type":"speaker","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Feiler bestochener Betrüger! (Fasst ihn hart an.)","type":"dialogue","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"HERMANN","type":"speaker","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Das bin ich nicht, gnädiges Fräulein. Seht selbst, ob's nicht Euer Bild ist – Ihr mögt es ihm wohl selbst gegeben haben.","type":"dialogue","page":25,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Mein, mein! O Himmel und Erde!","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR  (schreiend, sein Gesicht zerfleischend)","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Mein Fluch ihn gejagt in den Tod! gefallen in Verzweiflung!","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"FRANZ","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Und er gedachte meiner in seiner letzten Stunde.","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR  (lallend)","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Mein Fluch ihn gejagt in den Tod, gefallen mein Sohn in Verzweiflung! –","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"HERMANN","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Den Jammer steh' ich nicht aus. Lebt wohl, alter Herr! (Leise zu Franz.) Warum habt Ihr auch das gemacht, Junker? (Geht schnell ab.)","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA  (aufspringend, ihm nach)","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Bleib, bleib! Was waren seine letzten Worte?","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"HERMANN  (zurückrufend)","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Sein letzter Seufzer war Amalia. (Ab.)","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Sein letzter Seufzer war Amalia! – Nein, du bist kein Betrüger! So ist es wahr – wahr – er ist tot! (taumelnd, bis sie umsinkt) Karl ist tot.","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"FRANZ","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Was steht da auf dem Schwert? mit Blut – Amalia- verlass meine Amalia nicht. Sieh doch! sieh doch! – und auf der andern Seite: Amalia, deinen Eid zerbrach der allgewaltige Tod. – Siehst du nun, siehst du nun?","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Er hat mich nie geliebt! (Schnell ab.)","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"FRANZ  (auf den Boden stampfend)","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Wehe, wehe! Verlass mich nicht, meine Tochter!","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Franz, Franz! gib mir meinen Sohn wieder!","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"FRANZ","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Wer war's, der ihm den Fluch gab? Wer war's, der seinen Sohn jagte in Kampf und Tod und Verzweiflung? – Oh! er war ein Engel, ein Kleinod des Himmels. Fluch über seine Henker! Fluch, Fluch über Euch selber! –","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR  (schlägt mit geballter Faust wider Brust und Stirn)","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Er war ein Engel, war Kleinod des Himmels! Fluch, Fluch, Verderben, Fluch über mich selber! Ich bin der Vater, der seinen großen Sohn erschlug. Mich liebt' er bis in den Tod! mich zu rächen, rannte er in Kampf und Tod! Ungeheuer, Ungeheuer!","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"FRANZ","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Er ist dahin, was helfen späte Klagen? (Höhnisch lachend.)","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Hin, verloren auf ewig! Und du hast mir den Fluch aus dem Herzen geschwätzt, du – du – Meinen Sohn mir wieder!","type":"dialogue","page":26,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"FRANZ","type":"speaker","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Kraftlose Knochen! ihr wagt es – Sterbt! Verzweifelt! (Ab.)","type":"dialogue","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"DER ALTE MOOR","type":"speaker","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Du hast mir meinen Sohn aus den Armen gestohlen. Verzweifeln, aber nicht sterben! – Sie fliehen, verlassen mich im Tode. Keine Söhne! keine Töchter! keine Freunde! – Menschen nur –","type":"dialogue","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"KARL","type":"speaker","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Menschen – Menschen! falsche, heuchlerische Krokodilbrut.","type":"dialogue","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Amalia mit verweinten Augen.","type":"direction","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"DER ALTE MOOR","type":"speaker","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Ich hab' meinen Sohn ermordet!","type":"dialogue","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Ihr habt einen herrlichen Sohn verloren.","type":"dialogue","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"FRANZ","type":"speaker","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Habt Ihr genug um Euren Sohn geweint? So viel ich sehe, habt Ihr nur einen.","type":"dialogue","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Mir wird sehr übel.","type":"dialogue","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Was ist das?","type":"dialogue","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Das ist der Tod! – Schwarz – schwimmt – vor meinen – Augen – ich bitt' dich – ruf dem Pastor – dass er mir – das Abendmahl reiche – Wo ist – mein Sohn Franz?","type":"dialogue","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Er ist geflohen! Gott erbarme sich unser!","type":"dialogue","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Geflohen – geflohen von des Sterbenden Bette? – Und das all – all – von zwei Söhnen voll Hoffnung – du hast sie – gegeben – hast sie – genommen – – dein Name sei – –","type":"dialogue","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"AMALIA  (mit einem plötzlichen Schrei)","type":"speaker","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Tod! Alles tot! (Ab in Verzweiflung.)","type":"dialogue","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Franz hüpft frohlockend herein.","type":"direction","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Tot, schreien sie, tot! Jetzt bin ich Herr. Im ganzen Schlosse zetert es: tot. –","type":"dialogue","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"Wie aber, schläft er vielleicht nur? – Freilich, ach freilich! – Schlaf und Tod sind nur Zwillinge. Wir wollen einmal die Namen wechseln! Wackerer, willkommener Schlaf! Wir wollen dich Tod heißen! (Er drückt ihm die Augen zu.) Wer wird nun kommen und es wagen, mich vor Gericht zu fordern? oder mir ins Angesicht zu sagen: du bist ein Schurke! Nun sollt ihr den nackten Franz sehen und euch entsetzen! Streicheln und kosen ist meine Sache nicht. Ich will euch die zackigen Sporen ins Fleisch hauen. Blässe der Armut und sklavischen Furcht sind meine Leibfarbe. (Er geht ab.)","type":"dialogue","page":27,"act":"ZWEITER AKT","scene":"2. SZENE"},{"text":"3. SZENE","type":"scene","page":28,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Die böhmischen Wälder.","type":"setting","page":28,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RÄUBERHAUFEN","type":"speaker","page":28,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Stehlen, morden, huren, balgenheißt bei uns die Zeit zerstreun.Morgen hangen wir am Galgen,Drum lasst uns heute lustig sein.","type":"verse","page":28,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Ein freies Leben führen wir,Ein Leben voller Wonne;Der Wald ist unser Nachtquartier,Bei Sturm und Wind hantieren wir,Der Mond ist unsre Sonne.","type":"verse","page":28,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Spiegelberg. Razmann.","type":"direction","page":28,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN","type":"speaker","page":28,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Bist da? bist's wirklich? So lass dich doch zu Brei zusammendrücken, lieber Herzensbruder Moritz! Willkommen in den böhmischen Wäldern! Bist ja groß worden und stark.","type":"dialogue","page":28,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":28,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Das bin ich, wie du siehst, an Leib und Seele. Narr! einen Lass dir einen Spaß erzählen, den ich neulich im Cäcilien-Kloster angerichtet habe. Ich treffe das Kloster auf meiner Wanderschaft so gegen die Dämmerung, und da ich eben den Tag noch keine Patrone verschossen hatte – du weißt, ich hasse das auf den Tod – so musste die Nacht noch durch einen Streich verherrlicht werden.","type":"dialogue","page":28,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Wir halten uns ruhig bis in die späte Nacht. Es wird mausstill. Die Lichter gehen aus. Wir denken, die Nonnen könnten jetzt in den Federn sein. Nun nehm' ich meinen Kameraden Grimm mit mir, die andern warten vorm Tor. Schleich' mich hinein, wo die Nonnen schliefen, praktizier' ihnen die Kleider weg, und heraus mit ihnen zum Tor. Wir gehen weiter von Zelle zu Zelle, nehmen einer Schwester nach der andern die Kleider, endlich auch der Äbtissin – Jetzt pfeif' ich, und meine Kerls draußen fangen an zu stürmen und zu haselieren. Hahaha! – da hättest du die Hatz sehen sollen, wie die armen Tierchen in der Finsternis nach ihren Röcken tappten und sich jämmerlich gebärdeten. Wie sie zum Teufel waren, und wie sie sich vor Schreck und Bestürzung in Bettlaken wickelten, oder unter dem Ofen zusammenkrochen wie Katzen, andere in der Angst ihres Herzens die Stube so besprengten, dass du hättest das Schwimmen drin lernen können, und das erbärmliche Gezeter und Lamento. Kurzen Prozess gemacht: entweder heraus mit dem Silbergeschirr, mit dem Klosterschatz und den blanken Talern, oder – meine Kerls verstanden mich schon – ich sage dir, ich hab' aus dem Kloster mehr denn tausend Taler Werts geschleift, und den Spaß obendrein, und meine Kerls haben ihnen ein Andenken hinterlassen, sie werden ihre neun Monate dran zu schleppen haben.","type":"dialogue","page":28,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN  (auf den Boden stampfend)","type":"speaker","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Du bist ein ausgelernter Praktikus.","type":"dialogue","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Mein Gott! als ob ich noch jemals dran gezweifelt hätte. – Horch doch! was für ein Knall war das?","type":"dialogue","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN","type":"speaker","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Es war gedonnert, nur fortgemacht!","type":"dialogue","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Razmann! ich rieche Pulver –","type":"dialogue","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN","type":"speaker","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Gib Acht, es wird in der Näh was gesetzt haben! – Ja, ja, wie ich dir sage, Moritz, du wirst dem Hauptmann mit deinen Rekruten willkommen sein – er hat auch schon brave Kerl angelockt.","type":"dialogue","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Aber die meinen! die meinen! – Pah –","type":"dialogue","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN","type":"speaker","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Sie schämen sich nicht, unter ihm zu dienen. Er mordet nicht um des Raubes willen, wie wir – nach dem Geld schien er nicht mehr zu fragen, sobald er's vollauf haben konnte, er verschenkt an Waisenkinder, oder lässt damit arme Jungen von Hoffnung studieren. Aber soll er dir einen Landjunker schröpfen, der seine Bauern wie das Vieh abschindet, oder einen Schurken, der die Gesetze falschmünzt und das Auge der Gerechtigkeit übersilbert, oder sonst ein Herrchen von dem Gelichter – Kerl! da ist er dir in seinem Element und haust Teufel mäßig, als wenn jede Faser an ihm eine Furie wäre.","type":"dialogue","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"AMALIA","type":"speaker","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Er ist kein Dieb, der sich mit Schlaf und Mitternacht verschwört. Sein Handwerk ist Wiedervergeltung, Rache ist sein Gewerbe. Er mordet nicht um des Raubes Willen wie ihr.","type":"dialogue","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Hum! hum! Bruder, was ich dir vorhin erzählt habe, bleibt unter uns, er braucht's nicht zu wissen. Verstehst du?","type":"dialogue","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN","type":"speaker","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Recht, recht, ich versteh'.","type":"dialogue","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHWEIZER  (in vollem Lauf)","type":"speaker","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Hurtig, hurtig! wo sind die Andern? – Tausendsakerment! Ihr steht da und plaudert! Wisst ihr denn nicht – wisst ihr denn gar nicht? – und Roller –","type":"dialogue","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN","type":"speaker","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Was denn? was denn?","type":"dialogue","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHWARZ","type":"speaker","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Roller ist gehangen, noch vier Andere mit.","type":"dialogue","page":29,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN","type":"speaker","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Roller? Schwere Not! Weiß es der Hauptmann?","type":"dialogue","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Er schäumt wie ein Eber. Du weißt, er hat immer am meisten gehalten auf Roller, er selbst hat sich schon in Kapuziners Kutte zu ihm geschlichen und die Person mit ihm wechseln wollen; Roller schlug's hartnäckig ab; jetzt will er ihm eine Todesfackel anzünden, wie sie noch keinem König geleuchtet hat. Mir ist bang für die Stadt.","type":"dialogue","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN","type":"speaker","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Das ist wahr! ich kenne den Hauptmann. Aach, der arme Roller! der arme Roller! –","type":"dialogue","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Memento mori! Aber das regt mich nicht an. (Trillert ein Liedchen.)","type":"dialogue","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN  (aufspringend)","type":"speaker","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Horch! ein Schuss (Schießen und Lärmen.)","type":"dialogue","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Noch einer!","type":"dialogue","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN","type":"speaker","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Wieder einer! der Hauptmann!","type":"dialogue","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHUFTERLE · ROLLER  (hinter der Scene)","type":"speaker","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Holla ho! Holla ho!","type":"dialogue","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN","type":"speaker","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Roller! Roller! Holen mich zehn Teufel!","type":"dialogue","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Schufterle! Roller! Blitz, Donner, Hagel und Wetter! (Fliegen ihm entgegen.)","type":"dialogue","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RÄUBER MOOR  (zu Pferd)","type":"speaker","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Freiheit! Freiheit! – – Du bist im Trocknen, Roller! – Führ' meinen Rappen ab, Schweizer, und wasch' ihn mit Wein. (Wirft sich auf die Erde.) Das hat gegolten!","type":"dialogue","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN  (zu Roller)","type":"speaker","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Bist du vom Rad auferstanden? Bist du sein Geist? oder bin ich ein Narr? oder bist du's wirklich?","type":"dialogue","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"ROLLER  (in Atem)","type":"speaker","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Ich komme geradewegs vom Galgen her. Dem Hauptmann dank' ich Luft, Freiheit und Leben.","type":"dialogue","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Lass mich nur erst zu Atem kommen. Der Schweizer wird dir erzählen. Gebt mir ein Glas Branntwein! – Du auch wieder da, Moritz? Ich dachte, dich wo anders wieder zu sehen – Gebt mir doch ein Glas Branntwein! meine Knochen fallen auseinander – o mein Hauptmann! wo ist mein Hauptmann?","type":"dialogue","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN","type":"speaker","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"So sag doch, so schwätz doch! wie bist du davongekommen?","type":"dialogue","page":30,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Es war ein Spaß, der sich hören lässt. Auf! sagt der Hauptmann, was wiegt ein Freund nicht? – Wir retten ihn, oder retten ihn nicht, so wollen wir ihm wenigstens doch eine Todesfackel anzünden. Wir schicken einen Expressen an ihn, der's ihm in einem Zettelchen beibrachte, das er ihm in die Suppe warf.","type":"dialogue","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"ROLLER","type":"speaker","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Ich zweifelte an dem Erfolg.","type":"dialogue","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Hört, Canaillen! ich sag' euch, wenn man aus dem glühenden Ofen ins Eiswasser springt, kann man den Abfall nicht so stark fühlen, als ich, da ich am andern Ufer war.","type":"dialogue","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SPIEGELBERG  (lacht)","type":"speaker","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Armer Schlucker! Nun ist's ja verschwitzt. (Trinkt ihm zu.) Zur glücklichen Wiedergeburt!","type":"dialogue","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"ROLLER  (wirft sein Glas weg)","type":"speaker","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Nein, ich möchte das nicht zum zweiten Mal erleben. Sterben ist etwas mehr als Harlekins Sprung, und Todesangst ist ärger als Sterben.","type":"dialogue","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Gut, gut. Und wir haben ihnen eins angerichtet, dran sie vierzehn Tage werden zu löschen haben. Wenn sie dem Feuer wehren wollen, so müssen sie die Stadt durch Wasser ruinieren –","type":"dialogue","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Merkst du's jetzt, Razmann? – drum stank auch die Luft so nach Schwefel stundenweit, als würde die ganze Garderobe des Molochs unter dem Firmament ausgelüftet – Es war ein Meisterstreich, Hauptmann! ich beneide dich drum.","type":"dialogue","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Weißt du nicht, Schufterle, wie viel es Tote gesetzt hat?","type":"dialogue","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHUFTERLE","type":"speaker","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Drei und achtzig, sagt man. Der Turm allein hat ihrer sechzig zu Staub zerschmettert.","type":"dialogue","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RÄUBER MOOR  (sehr ernst)","type":"speaker","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Roller, du bist teuer bezahlt","type":"dialogue","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHUFTERLE","type":"speaker","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Pah! pah! was heißt aber das? – ja, wenn's Männer gewesen wären – aber da waren's Wickelkinder, die ihre Laken vergolden, eingeschnürte Mütterchen, die ihnen die Mücken wehrten, ausgedörrte Ofenhocker, die keine Türe mehr finden konnten – Patienten, die nach dem Doktor winselten, und nur der Bodensatz der Stadt blieb zurück, die Häuser zu hüten.","type":"dialogue","page":31,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"MOOR","type":"speaker","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Oh, der armen Gewürme! Kranke, sagst du, Greise und Kinder? –","type":"dialogue","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Wirklich, Schufterle? Fort! Ungeheuer! Lass dich nimmer unter meiner Bande sehen! – Murrt ihr? Überlegt ihr? – Wer überlegt, wenn ich befehle? – Fort mit ihm, sag' ich – Es sind noch mehr unter euch, die meinem Grimm reif sind. Ich kenne dich, Spiegelberg. Aber ich will nächstens unter euch treten und fürchterlich Musterung halten.","type":"dialogue","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Schufterle ab.","type":"direction","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Razmann, Roller, Schweizer- abseits","type":"direction","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"MOOR  (allein, heftig auf und ab gehend)","type":"speaker","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Was kann ich dafür? Wer kann der Flamme befehlen, dass sie nicht auch durch die gesegneten Saaten wüte. – O pfui über den Kindermord! den Weibermord! den Krankenmord! – Wie beugt mich diese Tat! Sie hat meine schönsten Werke vergiftet. Hier entsag' ich dem frechen Plan, gehe, mich in irgendeine Kluft der Erde zu verkriechen, wo der Tag vor meiner Schande zurücktritt. (Er will fliehen.)","type":"dialogue","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RÄUBER  (eilig)","type":"speaker","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Sieh dich vor, Hauptmann! Es spukt! Ganze Haufen böhmischer Reiter schwadronieren um Holz herum.","type":"dialogue","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Hauptmann, Hauptmann! Sie haben uns die Spur abgelauert – rings ziehen ihre etliche tausend einen Kette um den mittleren Wald.","type":"dialogue","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"ROLLER","type":"speaker","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Weh, weh, weh! Wir sind gefangen.","type":"dialogue","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"(Moor geht ab.)","type":"direction","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN","type":"speaker","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Wo ist der Hauptmann?","type":"dialogue","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Ist die ganze Bande beisammen? Wo ist der Hauptmann? Wir haben doch Pulver genug.","type":"dialogue","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"ROLLER","type":"speaker","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Aber unser sind achtzig in Allem, und so immer kaum Einer gegen ihrer Zwanzig.","type":"dialogue","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Desto besser! und lass es fünfzig gegen meinen großen Nagel sein – Wo, zum Teufel! ist denn der Hauptmann?","type":"dialogue","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Er verlässt uns in dieser Not. Können wir denn nicht mehr entwischen?","type":"dialogue","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Entwischen? Dreckseele du! Bei nackten Nonnen hast du ein großes Maul, aber wenn du zwei Fäuste siehst, – Memme, zeige dich jetzt.","type":"dialogue","page":32,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"RAZMANN","type":"speaker","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Der Hauptmann, der Hauptmann!","type":"dialogue","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Moorlangsam vor sich.","type":"direction","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"MOOR","type":"speaker","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Ich habe sie vollends ganz einschließen lassen, jetzt müssen sie fechten wie Verzweifelte. (Laut.) Kinder! Nun gilt's! Wir sind verloren, oder wir müssen fechten wie angeschossene Eber. Ist die ganze Bande zusammen? Es fehlt doch an Pulver nicht?","type":"dialogue","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHWEIZER  (springt auf)","type":"speaker","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Wir haben Pulver genug!","type":"dialogue","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Da gehörst du hin, Spiegelberg!","type":"dialogue","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"PATER  (vor sich, stutzt)","type":"speaker","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Ist Das das Drachennest? – Ich bin ein Diener der Kirche, und draußen stehen Siebenzehnhundert, die jedes Haar auf meinen Schläfen bewachen.","type":"dialogue","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"MOOR","type":"speaker","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Sagen Sie kurz, Herr Pater! was haben Sie hier zu tun?","type":"dialogue","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"PATER","type":"speaker","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Mich sendet die hohe Obrigkeit, die über Leben und Tod spricht – Ihr Diebe – ihr Mordbrenner, – ihr Schelmen – giftige Otterbrut, die im Finstern schleicht und im Verborgenen sticht – Aussatz der Menschheit – Höllenbrut, – köstliches Mahl für Raben und Ungeziefer - Gaunerkönig!","type":"dialogue","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"MOOR","type":"speaker","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Sehr wahr, sehr wahr! Nur weiter!","type":"dialogue","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"PATER","type":"speaker","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Was? sehr wahr, sehr wahr? Ist das auch eine Antwort?","type":"dialogue","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"MOOR","type":"speaker","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Wie, mein Herr? drauf haben Sie sich wohl nicht gefasst gemacht? Weiter, nur weiter! Was wollten Sie weiter sagen?","type":"dialogue","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"PATER","type":"speaker","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Dass ein Bösewicht noch so stolz sein kann!","type":"dialogue","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"(Wendet sich zu der Bande.) So hört, was die Gerechtigkeit euch durch mich zu wissen tut! – Werdet ihr diesen verurteilten Missetäter gebunden überliefern, seht, so soll euch die Strafe eurer Gräuel erlassen sein – nun, nun? Wie schmeckt das, Majestät? – Frisch also! Bindet ihn, und seid frei!","type":"dialogue","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"MOOR","type":"speaker","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Hört ihr's auch? Hört ihr? Was stutzt ihr? Was steht ihr verlegen da? Sie bietet euch Freiheit, und ihr seid wirklich schon ihre Gefangenen.","type":"dialogue","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Helfen Sie doch, Herr Pater!","type":"dialogue","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"PATER  (vor sich)","type":"speaker","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Ist der Kerl unsinnig? – (Laut.) Sorgt ihr etwa, dass dies eine Falle sei, euch lebendig zu fangen? – Lest selbst, hier ist der Generalpardon unterschrieben. (Er gibt Schweizern ein Papier.) Könnt ihr noch zweifeln?","type":"dialogue","page":33,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"MOOR","type":"speaker","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Geh hin und sage dem hochlöblichen Gericht, das über Leben und Tod würfelt – Ich bin kein Dieb, der sich mit Schlaf und Mitternacht verschwört. Rache ist mein Gewerbe.","type":"dialogue","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Bemerken Sie die vier kostbaren Ringe, die ich an jedem Finger trage? – Diesen Rubin zog ich einem Minister vom Finger, den ich auf der Jagd zu den Füßen seines Fürsten niederwarf. Er hatte sich aus dem Pöbelstaub zu seinem ersten Günstling emporgeschmeichelt. Diesen Diamant zog ich einem Finanzrat ab, der Ehrenstellen und Ämter an die Meistbietenden verkaufte. Diesen Achat trag' ich einem Pfaffen Ihres Gelichters zur Ehre, den ich mit eigener Hand erwürgte, als er auf offener Kanzel geweint hatte, dass die Inquisition so in Zerfall käme – ich könnte Ihnen noch mehr Geschichten von meinen Ringen erzählen, wenn mich nicht schon die paar Worte gereuten, die ich mit Ihnen verschwendet habe –","type":"dialogue","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Schafft ihn aus meinen Augen!","type":"dialogue","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"PATER","type":"speaker","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Du willst also nicht Schonung und Gnade? – Gut, mit dir bin ich fertig. Und was kann euer Los anders sein? Wankt ihr noch? Ist es so schwer, zwischen Himmel und Hölle zu wählen? Bindet ihn, und ihr seid frei!","type":"dialogue","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Wer ist der Erste, der seinen Hauptmann in der Not verlässt?","type":"dialogue","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"ROLLER","type":"speaker","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Wer kein Hund ist, rette den Hauptmann!","type":"dialogue","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"SCHWEIZER  (zerreißt den Pardon und wirft die Stücke dem Pater ins Gesicht)","type":"speaker","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Rettet, rettet den Hauptmann!","type":"dialogue","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"ALLE  (lärmen)","type":"speaker","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Rettet, rettet, rettet den Hauptmann!","type":"dialogue","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"MOOR  (sich losreißend, freudig)","type":"speaker","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"Jetzt sind wir frei – Kameraden! Tod oder Freiheit!","type":"dialogue","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"(Man bläst zum Angriff. Lärm und Getümmel. Sie gehen ab mit gezogenem Degen.)","type":"direction","page":34,"act":"ZWEITER AKT","scene":"3. SZENE"},{"text":"DRITTER AKT","type":"act","page":35,"act":"DRITTER AKT","scene":null},{"text":"1. SZENE","type":"scene","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Amalia im Garten","type":"setting","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Schon wieder hier, eigensinnige Schwärmerin? Du hast dich vom frohen Mahle hinweggestohlen und den Gästen die Freude verdorben.","type":"dialogue","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"AMALIA","type":"speaker","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Schade für diese unschuldigen Freuden! das Totenlied muss noch in deinen Ohren murmeln, das deinem Vater zu Grabe hallte –","type":"dialogue","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Willst du denn ewig klagen? Lass die Toten schlafen und mache die Lebendigen glücklich! Ich komme –","type":"dialogue","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"AMALIA","type":"speaker","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Und wann gehst du wieder?","type":"dialogue","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Kein so finsteres stolzes Gesicht! du betrübst mich, Amalia. Ich komme, dir zu sagen –","type":"dialogue","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"AMALIA","type":"speaker","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Ich muss wohl hören, Franz von Moor ist ja gnädiger Herr worden.","type":"dialogue","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Ja recht, das war's, worüber ich dich vernehmen wollte – Maximilian ist schlafen gegangen in der Väter Gruft. Ich bin Herr. Aber ich möchte es vollends ganz sein, Amalia. – Du weißt, was du unserm Hause warst, du wardst gehalten wie Moors Tochter, selbst den Tod überlebte seine Liebe zu dir, das wirst du wohl niemals vergessen?","type":"dialogue","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"AMALIA","type":"speaker","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Niemals, niemals. Wer das auch so leichtsinnig beim frohen Mahle hinwegzechen könnte!","type":"dialogue","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Die Liebe meines Vaters musst du in seinen Söhnen belohnen, und Karl ist tot – Staunst du? schwindelt dir? Ja wahrhaftig, der Gedanke ist auch so schmeichelnd erhaben, dass er selbst den Stolz eines Weibes betäubt. Franz tritt die Hoffnungen der edelsten Fräuleins mit Füßen, Franz kommt und bietet einer armen, ohne ihn hilflosen Waise sein Herz, seine Hand und mit ihr all sein Gold an und all seine Schlösser und Wälder. Franz, der Beneidete, der Gefürchtete, erklärt sich freiwillig für Amalias Sklaven –","type":"dialogue","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"AMALIA","type":"speaker","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Warum spaltet der Blitz die ruchlose Zunge nicht, die das Frevelwort ausspricht! Du hast meinen Geliebten ermordet, und Amalia soll dich Gemahl nennen! Du –","type":"dialogue","page":35,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Nicht so ungestüm, allergnädigste Prinzessin! – Franz spricht, und wenn man nicht antwortet, so wird er – befehlen.","type":"dialogue","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"AMALIA","type":"speaker","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Wurm du, befehlen? mir befehlen? lacht","type":"dialogue","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Das wirst du nicht. Noch weiß ich Mittel, die den Stolz eines Starrkopfs so hübsch niederbeugen können – Diese ewige Grille von Karl soll dir mein Anblick gleich einer feuerhaarigen Furie aus dem Kopfe geißeln; das Schreckbild Franz soll hinter dem Bild deines Lieblings im Hinterhalt lauern, gleich dem verzauberten Hund, der auf unterirdischen Goldkästen liegt – an den Haaren will ich dich in die Kapelle schleifen, den Degen in der Hand dir den ehelichen Schwur aus der Seele pressen, dein jungfräuliches Bette im Sturm ersteigen und deine stolze Scham mit noch größerem Stolze besiegen.","type":"dialogue","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"AMALIA  (gibt ihm eine Maulschelle)","type":"speaker","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Nimm erst das zur Aussteuer hin.","type":"dialogue","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"FRANZ  (aufgebracht)","type":"speaker","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Nicht meine Gemahlin – die Ehre sollst du nicht haben – meine Maitresse sollst du werden. (Will sie fortreißen.)","type":"dialogue","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"AMALIA  (fällt ihm um den Hals)","type":"speaker","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Verzeih mir, Franz! (Wie er sie umarmen will, reißt sie ihm den Degen von der Seite und tritt hastig zurück.) Siehst du, Bösewicht, was ich jetzt aus dir machen kann? – Ich bin ein Weib, aber ein rasendes Weib – Wag' es einmal mit unzüchtigem Griff meinen Leib zu betasten – dieser Stahl soll deine geile Brust mitten durchrennen, und der Geist meines Oheims wird mir die Hand dazu führen. Fleuch auf der Stelle! (Sie jagt ihn davon.)","type":"dialogue","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Ah! wie mir wohl ist! – Jetzt kann ich frei atmen – ich fühlte mich stark. (Sie will gehen.)","type":"dialogue","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Hermann tritt schüchtern herein.","type":"direction","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Fräulein Amalia! Fräulein Amalia!","type":"dialogue","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"AMALIA","type":"speaker","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Unglücklicher! Was störest du mich?","type":"dialogue","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Ich hab' Euch sehr beleidigt. So höret nur ein einziges Wort – es wird Euch all' Eure Ruhe wiedergeben.","type":"dialogue","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"AMALIA  (kommt zurück und blickt ihn verwundernd an)","type":"speaker","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Wer im Himmel und auf Erden kann mir meine Ruhe wiedergeben? –","type":"dialogue","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Das kann von meinen Lippen ein einziges Wort – Höret mich an!","type":"dialogue","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Karl lebt noch!","type":"dialogue","page":36,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"AMALIA  (schreiend)","type":"speaker","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Unglücklicher!","type":"dialogue","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Nicht anders – Nun noch ein Wort – Euer Oheim –","type":"dialogue","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"AMALIA  (gegen ihn her stürzend)","type":"speaker","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Du lügst –","type":"dialogue","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Euer Oheim –","type":"dialogue","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"AMALIA","type":"speaker","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Karl lebt noch!","type":"dialogue","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Und Euer Oheim –","type":"dialogue","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"AMALIA","type":"speaker","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Karl lebt noch?","type":"dialogue","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"HERMANN","type":"speaker","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Auch Euer Oheim – Verratet mich nicht. (Eilt hinaus.)","type":"dialogue","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"AMALIA  (steht lang wie versteinert. Dann fährt sie wild auf, eilt ihm nach)","type":"speaker","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"Karl lebt noch!","type":"dialogue","page":37,"act":"DRITTER AKT","scene":"1. SZENE"},{"text":"2. SZENE","type":"scene","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Gegend an der Donau.","type":"setting","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Die Räuber gelagert auf einer Anhöhe unter Bäumen, die Pferde weiden den Hügel hinunter.","type":"setting","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Hier muss ich liegen bleiben. (Wirft sich auf die Erde.) Meine Glieder wie abgeschlagen. Meine Zunge trocken wie eine Scherbe.","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Seht doch, wie schön das Getreide steht! – Die Bäume brechen fast unter ihrem Segen. – Der Weinstock voll Hoffnung.","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"RAZMANN","type":"speaker","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Es gibt ein fruchtbares Jahr.","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Aber es kann ja über Nacht ein Hagel fallen und Alles zu Grund schlagen.","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Das ist leicht möglich. Es kann Alles zu Grund gehen, wenig Stunden vorm Schneiden.","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Das sag' ich ja. Es wird Alles zu Grund gehn. Ich habe die Menschen gesehen, ihre Bienensorgen und ihre Riesenprojekte und ihre Mäusegeschäfte- am Ende war kein Treffer darin. Es ist ein Schauspiel, Bruder, das Tränen in deine Augen lockt, wenn es dein Zwerchfell zum Gelächter kitzelt.","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Wie herrlich die Sonne dort untergeht!","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"So stirbt ein Held!","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"GRIMM","type":"speaker","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Du scheinst tief gerührt.","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Es war eine Zeit – Lasst mich allein, Kameraden. Es war eine Zeit, wo ich nicht schlafen konnte, wenn ich mein Nachtgebet vergessen hatte –","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Heitre dich auf. Sieh diese malerische Landschaft – den lieblichen Abend.","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Ja, Freunde! diese Welt ist so schön.","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Diese Erde so herrlich.","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Und ich ein Ungeheuer auf dieser herrlichen Erde.","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"GRIMM","type":"speaker","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"O weh, o weh!","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Die ganze Welt eine Familie und ein Vater dort oben – Mein Vater nicht – ich allein der Verstoßene. Umlagert von Mördern.","type":"dialogue","page":38,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"RAZMANN  (zu den Übrigen)","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Unbegreiflich! ich habe ihn nie so gesehen.","type":"dialogue","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Dass ich wiederkehren dürfte in meiner Mutter Leib! Ihr Tage des Friedens! du Schloss meines Vaters – ihr grünen schwärmerischen Täler!","type":"dialogue","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Dahin! dahin, unwiederbringlich! –","type":"dialogue","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER  (mit Wasser im Hut)","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Sauf zu, Hauptmann – hier ist Wasser genug, und frisch wie Eis.","type":"dialogue","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR  (gibt ihm den Hut zurück und wischt ihm sein Gesicht ab)","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Sonst sieht man ja die Narben nicht, die die böhmischen Reiter in deine Stirne gezeichnet haben – dein Wasser war gut, Schweizer – diese Narben stehen dir schön.","type":"dialogue","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Pah! hat noch Platz genug für ihrer dreißig.","type":"dialogue","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Ja, Kinder – es war ein heißer Nachmittag – und nur einen Mann verloren – mein Roller starb einen schönen Tod. (Er wischt sich die Augen.) Wie viel waren's doch von den Feinden, die auf dem Platz blieben?","type":"dialogue","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Hundert und sechzig Husaren – drei und neunzig Dragoner, gegen vierzig Jäger – dreihundert in Allem.","type":"dialogue","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Dreihundert für Einen! – Jeder von euch hat Anspruch an diesen Scheitel! (Er entblößt sich das Haupt.) Hier heb' ich meinen Dolch auf. So wahr meine Seele lebt! Ich will euch niemals verlassen.","type":"dialogue","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Schwöre nicht! Du weißt nicht, ob du nicht noch glücklich werden und bereuen wirst.","type":"dialogue","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Bei den Gebeinen meines Rollers! Ich will euch niemals verlassen.","type":"dialogue","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Kosinsky kommt.","type":"direction","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Gebt Acht! wer kommt da?","type":"dialogue","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Wie ist dein Name?","type":"dialogue","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"KOSINSKY","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"KOSINSKY","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Ich bin vier und zwanzig Jahr alt, aber ich habe Degen blinken gesehen und Kugeln um mich surren gehört.","type":"dialogue","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"So, junger Herr? –","type":"dialogue","page":39,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"KOSINSKY","type":"speaker","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Höre die Geschichte meines Unglücks. –","type":"dialogue","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Ich will sie hören.","type":"dialogue","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"KOSINSKY","type":"speaker","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Ich bin ein böhmischer Edelmann und wurde durch den frühen Tod meines Vaters Herr eines ansehnlichen Ritterguts. Die Gegend war paradiesisch – denn sie enthielt einen Engel – ein Mädchen, geschmückt mit allen Reizen der blühenden Jugend und keusch wie das Licht des Himmels. Doch, wem sag' ich das? Es schallt an euren Ohren vorüber – ihr habt niemals geliebt, seid niemals geliebt worden –","type":"dialogue","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Sachte, sachte! unser Hauptmann wird feuerrot.","type":"dialogue","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Hör' auf! ich will's ein andermal hören – morgen, nächstens, oder – wenn ich Blut gesehen habe.","type":"dialogue","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"KOSINSKY","type":"speaker","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Sie war bürgerlicher Geburt, eine Deutsche – aber ihr Anblick schmolz die Vorurteile des Adels hinweg. Mit der schüchternsten Bescheidenheit nahm sie den Trauring von meiner Hand, und übermorgen sollte ich meine Amalia vor den Altar führen.","type":"dialogue","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR  (steht schnell auf)","type":"speaker","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"KOSINSKY","type":"speaker","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Mitten im Taumel der auf mich wartenden Seligkeit, unter den Zurüstungen zur Vermählung – werd' ich durch einen Expressen nach Hof zitiert. Ich stellte mich. Man zeigte mir Briefe, die ich geschrieben haben sollte, voll verräterischen Inhalts. Ich errötete über der Bosheit – man nahm mir den Degen ab, warf mich ins Gefängnis, alle meine Sinnen waren hinweg.","type":"dialogue","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Nur weiter! ich rieche den Braten schon.","type":"dialogue","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"KOSINSKY","type":"speaker","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Hier lag ich einen Monat lang und wusste nicht, wie mir geschah. Mir bangte für meine Amalia. Endlich erschien der erste Minister des Hofes, wünschte mir zur Entdeckung meiner Unschuld Glück mit zuckersüßen Worten, liest mir den Brief der Freiheit vor, gibt mir meinen Degen wieder. Jetzt im Triumphe nach meinem Schloss, in die Arme meiner Amalia zu fliegen, – sie war verschwunden. Man hatte ihr die Wahl gelassen, ob sie mich lieber sterben sehen, oder die Maitresse des Fürsten werden wollte. Im Kampf zwischen Ehre und Liebe entschied sie für das Zweite, und (lachend) ich war gerettet.","type":"dialogue","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR  (der bisher in heftigen Bewegungen hin und her gegangen, springt rasch auf, zu den Räubern)","type":"speaker","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Sie weint. Sie vertrauert ihr Leben. Ich muss sie sehen – Auf! rafft zusammen – du bleibst, Kosinsky.","type":"dialogue","page":40,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"DIE RÄUBER","type":"speaker","page":41,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Wohin, was?","type":"dialogue","page":41,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":41,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Wohin? wer fragt wohin? (Heftig zu Schweizern.) Verräter, du willst mich zurückhalten? Aber bei der Hoffnung des Himmels! –","type":"dialogue","page":41,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":41,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Verräter ich? – Geh in die Hölle, ich folge dir!","type":"dialogue","page":41,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":41,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"Bruderherz! du folgst mir! Auf! hurtig! Alle! nach Franken! In acht Tagen müssen wir dort sein. (Sie gehen ab.)","type":"dialogue","page":41,"act":"DRITTER AKT","scene":"2. SZENE"},{"text":"VIERTER AKT","type":"act","page":42,"act":"VIERTER AKT","scene":null},{"text":"1. SZENE","type":"scene","page":42,"act":"VIERTER AKT","scene":"1. SZENE"},{"text":"Ländliche Gegend um das Moorische Schloss.","type":"setting","page":42,"act":"VIERTER AKT","scene":"1. SZENE"},{"text":"Räuber Moor.","type":"setting","page":42,"act":"VIERTER AKT","scene":"1. SZENE"},{"text":"MOOR","type":"speaker","page":42,"act":"VIERTER AKT","scene":"1. SZENE"},{"text":"Sei mir gegrüßt, Vaterlandserde! Vaterlandshimmel! Vaterlandssonne! Seid alle, alle mir herzlich gegrüßt! – da warst du so glücklich, warst so ganz,","type":"dialogue","page":42,"act":"VIERTER AKT","scene":"1. SZENE"},{"text":"und nun – da liegen die Trümmer deiner Entwürfe! Hier solltest du wandeln, ein großer, stattlicher, gepriesener Mann – hier dein Knabenleben in Amalias blühenden Kindern zum zweiten Mal leben – hier! hier- aber der böse Feind schmollte dazu!","type":"dialogue","page":42,"act":"VIERTER AKT","scene":"1. SZENE"},{"text":"(Er fährt auf.) Warum bin ich hierhergekommen? Dass mir's ginge wie dem Gefangenen, den der klirrende Eisenring aus Träumen der Freiheit aufjagt? – nein, ich gehe in mein Elend zurück! – Der Gefangene hatte das Licht vergessen, aber der Traum der Freiheit fuhr über ihm wie ein Blitz in die Nacht, der sie finsterer zurücklässt – Lebt wohl, ihr Vaterlandstäler! einst saht ihr den Knaben Karl, und der Knabe Karl war ein glücklicher Knabe – jetzt saht ihr den Mann,","type":"dialogue","page":42,"act":"VIERTER AKT","scene":"1. SZENE"},{"text":"Amalia Auftritt","type":"direction","page":42,"act":"VIERTER AKT","scene":"1. SZENE"},{"text":"und er war in Verzweiflung.","type":"dialogue","page":42,"act":"VIERTER AKT","scene":"1. SZENE"},{"text":"Sie nicht sehen, nicht einen Blick? – nur eine Mauer zwischen mir und Amalia – Nein! sehen muss ich sie und muss ich ihn –","type":"dialogue","page":42,"act":"VIERTER AKT","scene":"1. SZENE"},{"text":"(Er kehrt um.) Vater! Vater! dein Sohn naht – Nur diese Stunde lass mir frei – Amalia! Vater! dein Karl naht! Sei ein Mann! (Er geht hinein.)","type":"direction","page":42,"act":"VIERTER AKT","scene":"1. SZENE"},{"text":"2. SZENE","type":"scene","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Galerie im Schloss.","type":"setting","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Räuber Moor. Amalia.","type":"setting","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Karl betrachtet Bilder(galerie), bleibt an Maximilians Bild stehen","type":"direction","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"MOOR  (in seinem Anblick versunken)","type":"speaker","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Vater, Vater! vergib mir! – Ein vortrefflicher Mann! – (Er wischt sich die Augen.)","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Sie scheinen viel Anteil an ihm zu nehmen.","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Oh, ein vortrefflicher Mann – und er sollte dahin sein?","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Dahin! wie unsere besten Freuden dahin gehn – (Sanft seine Hand ergreifend.) Lieber Herr Graf,","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Graf von Brandt, aus Mecklenburg.","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Alles lebt, um traurig wieder zu sterben. Wir gewinnen nur darum, dass wir wieder mit Schmerzen verlieren.","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Sie verloren schon etwas?","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Nichts! Alles! Nichts – wollen wir weiter gehen, Herr Graf?","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"So eilig? Was ist dies Bild rechter Hand dort?","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Das Bild linker Hand ist der Sohn des Grafen, der wirkliche Herr – Kommen Sie, kommen Sie!","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Dies Bild dort?","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Sie wollen nicht in den Garten gehn?","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Du weinst, Amalia?","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"AMALIA  (schnell ab)","type":"speaker","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"MOOR","type":"speaker","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Sie liebt mich! sie liebt mich! –","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Elender, das verdientest du um sie! Steh' ich nicht hier wie ein Gerichteter! –","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Wo bin ich? Nacht vor meinen Augen. Ich, ich hab' ihn getötet! (Er rennt davon.)","type":"dialogue","page":43,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"FRANZ VON MOOR  (in tiefen Gedanken)","type":"speaker","page":44,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Weg mit diesem Bild! weg, feige Memme! Was zagst du, und vor wem?","type":"dialogue","page":44,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Ist's mir nicht die wenigen Stunden, die der Graf in diesen Mauern wandelt, als schlich' immer ein Spion der Hölle meinen Fersen nach – Ich sollt' ihn kennen!","type":"dialogue","page":44,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Es ist so was Großes in seinem wilden sonnenverbrannten Gesicht.","type":"dialogue","page":44,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Auch Amalia ist nicht gleichgültig gegen ihn!","type":"dialogue","page":44,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Es ist Karl! ja! – Er ist's! trotz seiner Larve! – Er ist's – trotz seiner Larve – Er ist's – Tod und Verdammnis! (Auf und ab mit heftigen Schritten.)","type":"dialogue","page":44,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Hab' ich darum meine Nächte verprasst, – darum Felsen hinweggeräumt und Abgründe eben gemacht, – bin ich darum gegen alle Instinkte der Menschheit rebellisch geworden?","type":"dialogue","page":44,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Sachte! nur sachte! – ans Umkehren ist doch nicht mehr zu denken –","type":"dialogue","page":44,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"– Es kommt Alles nur darauf an, wie man davon denkt, und Der ist ein Narr, der wider seine Vorteile denkt.","type":"dialogue","page":44,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Mord! wie eine ganze Hölle von Furien um das Wort flattert – die Natur vergaß einen Mann mehr zu machen. Heißt es nicht eben so viel, als: es war nichts und wird nichts, und um nichts wird kein Wort mehr gewechselt – der Mensch entsteht aus Morast, und watet eine Weile im Morast, und macht Morast, und gärt wieder zusammen in Morast.","type":"dialogue","page":44,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"Glückliche Reise, Herr Bruder! Bei mir wirst du nimmermehr Audienz bekommen. (Er geht ab.)","type":"dialogue","page":44,"act":"VIERTER AKT","scene":"2. SZENE"},{"text":"3. SZENE","type":"scene","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Anderes Zimmer im Schloss.","type":"setting","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Räuber Moor von der einen, Daniel von der andern.","type":"setting","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"MOOR  (hastig)","type":"speaker","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Wo ist das Fräulein?","type":"dialogue","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"DANIEL","type":"speaker","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Gnädiger Herr! Erlaubt einem armen Mann, Eure Hand zu küssen!","type":"dialogue","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Lieber, bester Karl!","type":"dialogue","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"MOOR","type":"speaker","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Freund, was sagst du? Ich verstehe dich nicht.","type":"dialogue","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"DANIEL","type":"speaker","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Ja, leugnet es nur, verstellt Euch! Schön, schön! Ihr seid immer mein bester, köstlicher Junker – Lieber Gott, daß ich alter Mann noch die Freude – dummer Tölpel ich, dass ich Euch nicht gleich – Ei du himmlischer Vater! So seid Ihr wiedergekommen, und der alte Herr ist unterm Boden, und da seid Ihr ja wieder – Da steht er ja leibhaftig wieder in der alten Stube!","type":"dialogue","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"MOOR","type":"speaker","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Seid Ihr vom hitzigen Fieber befallen? oder wollt Ihr eine Komödienrolle an mir probieren?","type":"dialogue","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"DANIEL","type":"speaker","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Pfui doch, pfui doch! Das ist nicht fein, einen alten Knecht so zum Besten haben – Diese Narbe! He, wisst Ihr noch? – Was Ihr mir da für Angst einjagtet – ich hab' Euch immer so liebgehabt, – wisst Ihr noch? – dort in der runden Stube – den Kuckuck, den Ihr so gern hörtet – da saßt Ihr mir im Schoß und rieft: Hotto! und ich lief fort, Euch den Hottegaul zu holen –– warum musst' ich alter Esel auch fortlaufen? – und wie ich das Zetergeschrei höre da lief das helle Blut. Großer Gott, wenn's ins Aug gegangen wäre – Mein Lebenstag, sagt' ich, soll mir kein Kind mehr ein Messer oder eine Schere in die Hände kriegen, sagt' ich – war zum Glück noch Herr und Frau verreiset – ja, ja, das soll mir mein Tag des Lebens eine Warnung sein, sagt' ich – Jemini, Jemini! ich hätte vom Dienst kommen können, ich hätte – aber Gottlob! es heilte glücklich, bis auf die wüste Narbe.","type":"dialogue","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"MOOR","type":"speaker","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Ich verstehe kein Wort von Allem, was du sagst.","type":"dialogue","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"DANIEL","type":"speaker","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Ja, lacht nur, lacht nur! Den alten Mann will man nicht kennen, da thut man so fremd, so fürnehm – o Ihr seid doch mein goldiger Junker – freilich halt ein Bischen luker gewesen – nehmt mir's nicht übel! – wie's eben das junge Fleisch meistens ist – am Ende kann noch Alles gut werden.","type":"dialogue","page":45,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"MOOR  (fällt ihm um den Hals)","type":"speaker","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Ja, Daniel, ich will's nicht mehr verhehlen! Ich bin dein Karl, dein verlorener Karl! Was macht meine Amalia?","type":"dialogue","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"DANIEL","type":"speaker","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Eure Amalia, oh, die wird's nicht überleben, die wird sterben vor Freude!","type":"dialogue","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"MOOR  (heftig)","type":"speaker","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Sie vergaß mich nicht?","type":"dialogue","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"DANIEL","type":"speaker","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Vergessen? Euch vergessen? – Ihr hättet's sehen sollen, wie sie sich gebärdete, als die Zeitung kam, Ihr wärt gestorben, die der gnädige Herr ausstreuen ließ –","type":"dialogue","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"MOOR","type":"speaker","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Was sagst du? der gnädige Herr, mein Bruder –","type":"dialogue","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"DANIEL","type":"speaker","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Der gnädige Herr, Euer Bruder! ab","type":"dialogue","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"MOOR  (auffahrend aus einer schrecklichen Pause)","type":"speaker","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Betrogen, betrogen! da fährt es über meine Seele wie der Blitz! – Spitzbübische Künste! Verfälscht, unterdrückst meine Briefe. Nicht du, Vater! Ja! Spitzbübische Künste! Mörder, Räuber durch spitzbübische Künste! Oh ich Ungeheuer von einem Toren. Es hätte mich einen Fußfall gekostet – es hätte mich eine Träne gekostet – oh ich blöder, blöder, blöder Tor! (Wider die Wand rennend). Ich hätte glücklich sein können –","type":"dialogue","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Kosinsky kommt.","type":"direction","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"MOOR","type":"speaker","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Auf! Sattle die Pferde! Wir müssen vor Sonnenuntergang noch über den Grenzen sein!","type":"dialogue","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"KOSINSKY","type":"speaker","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Die Pferde stehen gesattelt, Ihr könnt aufsitzen, wenn Ihr wollt.","type":"dialogue","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"MOOR","type":"speaker","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Warum so eilig? Soll ich sie nicht mehr sehn?","type":"dialogue","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"KOSINSKY","type":"speaker","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Ich zäume gleich wieder ab.","type":"dialogue","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"MOOR","type":"speaker","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"Noch einmal! ein Lebewohl noch! halt, Kosinsky! zehn Minuten noch – und wir sprengen davon!","type":"dialogue","page":46,"act":"VIERTER AKT","scene":"3. SZENE"},{"text":"4. SZENE","type":"scene","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Im Garten.","type":"setting","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"AMALIA","type":"speaker","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Du weinst, Amalia? – und das sprach er mit einer Stimme, mit einer Stimme.","type":"dialogue","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Nein, nein, weg aus meiner Seele, du Frevelbild! Im Herzen, wo Karl herrscht, darf kein Erdensohn nisten.","type":"dialogue","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"RÄUBER MOOR","type":"speaker","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Sie da, gnädiges Fräulein? – und traurig? – und eine Träne auf diesem Gemälde? Und wer ist der Glückliche?","type":"dialogue","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"AMALIA","type":"speaker","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Wenn Sie ihn gekannt hätten!","type":"dialogue","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Sie hätten ihn so liebgehabt – es war so viel, so viel in seinem Angesicht – in seinen Augen – im Ton seiner Stimme, das Ihnen so gleich kommt – das ich so liebe –","type":"dialogue","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"MOOR  (sieht zur Erde)","type":"speaker","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"MOOR","type":"speaker","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Er ist nicht mehr?","type":"dialogue","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"AMALIA","type":"speaker","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Er segelt auf ungestümen Meeren – Amalias Liebe segelt mit ihm. Sie scheinen traurig, Herr Graf?","type":"dialogue","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"MOOR","type":"speaker","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Die Worte der Liebe machen auch meine Liebe lebendig.","type":"dialogue","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"AMALIA","type":"speaker","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Was? Sie lieben eine Andre? – Weh mir, was hab' ich gesagt?","type":"dialogue","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"MOOR","type":"speaker","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Sie glaubte mich tot, und blieb treu dem Totgeglaubten. Sie weiß mich in Wüsten irren und im Elend herumschwärmen, und ihre Liebe fliegt durch Wüsten und Elend mir nach. Auch heißt sie Amalia, wie Sie, gnädiges Fräulein.","type":"dialogue","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"AMALIA","type":"speaker","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Wie beneide ich Ihre Amalia!","type":"dialogue","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"MOOR","type":"speaker","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Sie ist ein unglückliches Mädchen; ihre Liebe ist für einen, der verloren ist, und wird – ewig niemals belohnt.","type":"dialogue","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"AMALIA","type":"speaker","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Sie wird im Himmel belohnt. Sagt man nicht, es gebe eine bessere Welt, wo die Traurigen sich freuen und die Liebenden sich wieder erkennen?","type":"dialogue","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"MOOR","type":"speaker","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Ewigkeit heißt ihr Name – meine Amalia ist ein unglückliches Mädchen.","type":"dialogue","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"AMALIA","type":"speaker","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Unglücklich, und Sie lieben?","type":"dialogue","page":47,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"MOOR","type":"speaker","page":48,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Unglücklich, weil sie mich liebt! Wenn Ihr Geliebter Ihnen für jeden Kuss einen Mord aufzählen könnte? Wehe meiner Amalia! sie ist ein unglückliches Mädchen.","type":"dialogue","page":48,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"AMALIA","type":"speaker","page":48,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"Ha! wie bin ich ein glückliches Mädchen! Nicht eine Fliege konnte er leiden sehen – Seine Seele ist so fern von einem blutigen Gedanken, als fern der Mittag von der Mitternacht ist.","type":"dialogue","page":48,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"MOOR  (kehrt sich schnell ab in ein Gebüsch, blickt starr in die Gegend)","type":"speaker","page":48,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"AMALIA  (singt und spielt auf der Laute)","type":"speaker","page":48,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"singen zusammen?","type":"direction","page":48,"act":"VIERTER AKT","scene":"4. SZENE"},{"text":"5. SZENE","type":"scene","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Es wird Nacht, und der Hauptmann noch nicht da!","type":"dialogue","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"RAZMANN","type":"speaker","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Und versprach doch Schlag acht Uhr wieder bei uns einzutreffen.","type":"dialogue","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Wenn ihm etwas geschehen wäre – Kameraden! …","type":"dialogue","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SPIEGELBERG  (nimmt Razmann beiseite)","type":"speaker","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Auf ein Wort, Razmann.","type":"dialogue","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"GRIMM","type":"speaker","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Lass du ihn! Er wird einen Fang tun, dass wir uns schämen müssen.","type":"dialogue","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Er ging nicht von uns wie einer, der einen Schelmenstreich im Schild führt. Hast du vergessen, was er gesagt hat, als er uns über die Heide führte? – »Wer nur eine Rübe vom Acker stiehlt, lässt seinen Kopf hier, so wahr ich Moor heiße.« – Wir dürfen nicht rauben.","type":"dialogue","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"RAZMANN  (leise zu Spiegelberg)","type":"speaker","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Was willst du?","type":"dialogue","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Pst! Pst! – Ich weiß nicht, was du oder ich für Begriffe von Freiheit haben, dass wir an einem Karren ziehen, wie Stiere, und dabei wunderviel von Independenz deklamieren – Es gefällt mir nicht.","type":"dialogue","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SCHWEIZER  (zu Grimm)","type":"speaker","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Was wohl dieser Windkopf hier an der Kunkel hat?","type":"dialogue","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"RAZMANN  (leise zu Spiegelberg)","type":"speaker","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Du sprichst vom Hauptmann? –","type":"dialogue","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Pst doch! Pst! – Er hat so feine Ohren unter uns herumlaufen – Hauptmann, sagst du? wer hat ihn zum Hauptmann über uns gesetzt, oder hat er nicht diesen Titel usurpiert, der von Rechtswegen mein ist? – Wie, legen wir darum unser Leben auf Würfel – baden darum alle Milzsuchten des Schicksals aus, dass wir am Ende noch von Glück sagen, die Leibeigenen eines Sklaven zu sein? – Leibeigene, da wir Fürsten sein könnten? – Bei Gott! Razmann – das hat mir niemals gefallen.","type":"dialogue","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SCHWEIZER  (zu den andern)","type":"speaker","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Ja – du bist mir der rechte Held. – Frösche mit Steinen breit zu schmeißen…","type":"dialogue","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SPIEGELBERG  (zu Razmann)","type":"speaker","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Ja – und es soll anders werden. Razmann – – wenn du bist, wofür ich dich immer hielt – Razmann! mich däucht, seine schwarze Stunde schlägt –","type":"dialogue","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"RAZMANN","type":"speaker","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Ha, Satan! worin verstrickst du meine Seele?","type":"dialogue","page":49,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SPIEGELBERG","type":"speaker","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Ich hab' mir's gemerkt, wo er hinschlich – Komm! Zwei Pistolen fehlen selten, und dann – so sind wir die Ersten, die den Säugling erdrosseln. (Er will ihn fortreißen.)","type":"dialogue","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SCHWEIZER  (zieht wütend sein Messer)","type":"speaker","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Ha, Bestie! Eben recht erinnerst du mich an die böhmischen Wälder! – Warst du nicht die Memme, die anhub zu schnadern, als sie riefen: der Feind kommt?","type":"dialogue","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Fahr hin, Meuchelmörder! (Er sticht ihn tot.)","type":"dialogue","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"(wirft das Messer über ihn). Da! – und so krepier du. Die Bestie ist dem Hauptmann immer giftig gewesen und hat keine Narbe auf ihrer ganzen Haut –","type":"dialogue","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"GRIMM","type":"speaker","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Der Hauptmann wird rasend werden.","type":"dialogue","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Dafür lass mich sorgen –","type":"dialogue","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"RAZMANN","type":"speaker","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Horch, ein Pistolenschuss! (Man schießt wieder.) Noch einer! Holla! der Hauptmann!","type":"dialogue","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Moor tritt auf","type":"direction","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Sei willkommen, mein Hauptmann – Ich bin ein bisschen vorlaut gewesen, seit du weg bist. (Er führt ihn an die Leiche.) Sei du Richter zwischen mir und Diesem – von hinten hat er dich ermorden wollen.","type":"dialogue","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR  (nachdenkend)","type":"speaker","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Ich verstehe – Lenker im Himmel – ich verstehe – die Blätter fallen von den Bäumen – und mein Herbst ist kommen – Schafft mir Diesen aus den Augen! (Spiegelbergs Leiche wird hinweggetragen.)","type":"dialogue","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"GRIMM","type":"speaker","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Gib uns Order, Hauptmann – was sollen wir weiter tun?","type":"dialogue","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Ich habe mich selbst verloren, seit ich dort war – verlasst mich!","type":"dialogue","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"RÄUBER","type":"speaker","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Es ist Mitternacht, Hauptmann.","type":"dialogue","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Wie Blei liegt der Schlaf in uns. Seit drei Tagen kein Auge zu.","type":"dialogue","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Legt euch schlafen – Morgen am Tag gehen wir weiter.","type":"dialogue","page":50,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"RÄUBER","type":"speaker","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Gute Nacht, Hauptmann. (Sie lagern sich auf der Erde und schlafen ein.)","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Tiefe Stille.","type":"direction","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Moor nimmt die Laute und spielt.","type":"direction","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"(Er legt die Laute hin, geht tiefdenkend auf und nieder.)","type":"direction","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Es ist Alles so finster– kein Ausgang – Aus! (die Pistole vors Gesicht haltend)","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Nein, nein! es ist etwas mehr, denn ich bin noch nicht glücklich gewesen.","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Glaubt ihr, ich werde zittern? (Er setzt die Pistole an.) Zeit und Ewigkeit – aneinander gekettet durch ein einzig Moment!– Nein! nein! Ein Mann muss nicht straucheln – Sei, wie du willst, namenloses Jenseits.","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Du kannst mich zu nichts machen – Diese Freiheit kannst du mir nicht nehmen. (Er lädt die Pistole. Plötzlich hält er inne.) Soll ich dem Elend den Sieg über mich einräumen? – Nein! (Er wirft die Pistole weg.)","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"HERMANN  (kommt durch den Wald)","type":"speaker","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Horch, horch! grausig heulet der Kauz – zwölf schlägt's drüben im Dorf. (Tritt an das Schloss und pocht.) Komm herauf, Jammermann, Turmbewohner! – Deine Mahlzeit ist bereitet.","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR  (sachte zurücktretend)","type":"speaker","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Was soll das bedeuten?","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"EINE STIMME  (aus dem Schloss)","type":"speaker","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Bist du's, Hermann, mein Rabe?","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"HERMANN","type":"speaker","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Bin's, Hermann, dein Rabe.","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Vater…","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"DIE STIMME","type":"speaker","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Hab Dank, Rabensender,","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Vater…","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"STIMME","type":"speaker","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"fürs Brot in der Wüste!","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Vater…","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"HERMANN","type":"speaker","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Stille – Horch – Geräusche wie von Schnarchenden! Hörst du nicht was?","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"STIMME","type":"speaker","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Wie? Hörst du etwas?","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Vater…meines Vaters Stimme!","type":"dialogue","page":51,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"HERMANN  (Will fliehen.)","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Steh! Steh, sag' ich!","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"HERMANN","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Nun ist alles verraten!","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Steh! Rede! Wer bist du? was hast du hier zu tun? Rede!","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"HERMANN","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Nur ein Wort hört an, eh Ihr mich umbringt.","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Hier steckt ein Geheimnis – Heraus! Sprich! Ich will Alles wissen.","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"DIE STIMME  (aus dem Schloss)","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Bist du's, Hermann, der da redet? Mit wem redest du, Hermann?","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Vierfach geschlossen! Weg da – Es muss heraus – Jetzt zum ersten Mal -komm mir zu Hilfe, Dieberei!","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"(Er nimmt Brechinstrumente und öffnet das Gitterthor. Aus dem Grunde steigt ein Alter, ausgemergelt wie ein Gerippe.)","type":"direction","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"DER ALTE","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Erbarmen einem Elenden! Erbarmen!","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Das ist meines Vaters Stimme!","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Geist des alten Moors! was hat dich beunruhigt in deinem Grab?","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Ich bin kein Geist. Taste mich an, ich lebe, ein elendes, erbärmliches Leben!","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Was? du bist nicht begraben worden?","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Ich bin begraben worden – drei volle Monde schmacht' ich schon in diesem finstern unterirdischen Gewölbe, von keinem Strahle beschienen, von keinem warmen Lüftchen angeweht, von keinem Freunde besucht.","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Wer hat Das getan?","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Verfluch' ihn nicht! – Das hat mein Sohn Franz getan.","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Franz? Franz? Oh, ewiges Chaos!","type":"dialogue","page":52,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Ich lag eben auf dem Siechbett, hatte kaum angefangen, aus einer schweren Krankheit etwas Kräfte zu sammeln, so führte man einen Mann zu mir, der vorgab, mein Erstgeborener sei gestorben in der Schlacht. Ich ward ohnmächtig bei der Botschaft. Man muss mich für tot gehalten haben, denn als ich wieder zu mir selber kam, lag ich schon in der Bahre, und ins Leichentuch gewickelt wie ein Toter. Ich kratzte an dem Deckel der Bahre. Er ward aufgetan. Es war finstere Nacht, mein Sohn Franz stand vor mir. – Was? rief er mit entsetzlicher Stimme, willst du denn ewig leben? – und gleich flog der Sargdeckel wieder zu. Hinab mit dem Balg! donnerte es von seinem Munde, er hat genug gelebt, und hinab ward ich gestoßen ohne Erbarmen, und mein Sohn Franz schloss hinter mir zu.","type":"dialogue","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Es ist nicht möglich, nicht möglich! Ihr müsst Euch geirrt haben.","type":"dialogue","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Ich kann nicht geirrt haben. Ich kann mich geirrt haben. Höre weiter, aber zürne doch nicht! So lag ich zwanzig Stunden, und kein Mensch gedachte meiner Noth. Dieser Mann brachte mir Brot und Wasser. So ward ich kümmerlich erhalten, aber der unaufhörliche Frost – die faule Luft meines Unraths – der grenzenlose Kummer – meine Kräfte wichen, mein Leib schwand; tausendmal bat ich um den Tod, aber das Maß meiner Strafe muss noch nicht gefüllt sein. Aber ich leide gerecht – mein Karl! mein Karl! – und er hatte noch keine grauen Haare.","type":"dialogue","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Es ist genug. Auf! Auf! will Keiner erwachen?","type":"dialogue","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"DIE RÄUBER  (aufgejagt)","type":"speaker","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"He, was gibt's da?","type":"dialogue","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Hat euch die Geschichte nicht aus dem Schlummer gerüttelt? Auf! Schaut, der Sohn hat seinen Vater erschlagen.","type":"dialogue","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Nein, nicht erschlagen! das Wort ist Beschönigung! – der Sohn hat den Vater tausendmal gerädert, gespießt, gefoltert, geschunden! die Worte sind mir zu menschlich. Der Sohn hat seinen eigenen Vater – oh seht her, seht her! Es ist mein eigner Vater.","type":"dialogue","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"DIE RÄUBER","type":"speaker","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Dein Vater? dein Vater?","type":"dialogue","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Vater meines Hauptmanns! Du hast über meinen Dolch zu befehlen.","type":"dialogue","page":53,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Rache, Rache, Rache! So zerreiß' ich von nun an auf ewig das brüderliche Band.","type":"dialogue","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"So verfluch' ich jeden Tropfen brüderlichen Bluts. Höre mich, Mond und Gestirne! Höre mich, mitternächtlicher Himmel, der du auf die Schandtat herunterblicktest! Höre mich, dreimal schrecklicher Gott, der da oben über dem Monde waltet, und rächt und verdammt über den Sternen, und feuerflammt über der Nacht! Hier knie' ich – hier streck' ich empor die drei Finger – hier schwör' ich, wenn ich diesen Schwur verletze, schwör' ich, das Licht des Tages nicht mehr zu grüßen, bis des Vatermörders Blut, vor diesem Steine verschüttet, gegen die Sonne dampft. (Er steht auf.)","type":"dialogue","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"FRANZ","type":"speaker","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Schwimme, wer schwimmen kann, und wer zu plump ist, gehe unter. Jeder hat gleiches Recht zum Größten und zum Kleinsten. Anspruch wird ein Anspruch.","type":"dialogue","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Trieb an Trieb, Kraft an Kraft wohnt beim Überwältigsten. So geht es Gewissen. Blutliebe, Vaterliebe. Rache.","type":"dialogue","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Hauptmann! was sollen wir tun?","type":"dialogue","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Räche meinen Vater!","type":"dialogue","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Großer Hauptmann! heut hast du mich zum ersten Mal stolz gemacht!","type":"dialogue","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"MOOR","type":"speaker","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Zerr' ihn aus dem Bette, wenn er schläft, schlepp' ihn vom Mahle weg, wenn er besoffen ist, reiß ihn vom Kruzifix, liefere ihn mir nicht tot! Ganz muss ich ihn haben. Hast du mich verstanden, so eile davon!","type":"dialogue","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"Genug, Hauptmann! – hier hast du meine Hand darauf: Entweder du siehst Zwei zurückkommen oder gar Keinen.","type":"dialogue","page":54,"act":"VIERTER AKT","scene":"5. SZENE"},{"text":"FÜNFTER AKT","type":"act","page":55,"act":"FÜNFTER AKT","scene":null},{"text":"1. SZENE","type":"scene","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Franz im Schlafrock hereingestürzt.","type":"direction","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Mein Herr! (Löscht die Laterne aus.)","type":"dialogue","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Verraten! Verraten! Geister ausgespien aus Gräbern. Mörder! Mörder! – rufen sie.","type":"dialogue","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Herr, was schreit Ihr, dass alle Schläfer auffahren?","type":"dialogue","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Schläfer? Wer heißt euch schlafen? Es soll Niemand schlafen in dieser Stunde. Hörst du? Sahst du sie…?","type":"dialogue","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Wen, gnädiger Herr?","type":"dialogue","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Wen, Dummkopf, wen? Wen, Eselskopf, wen? Geister und Teufel! Wie weit ist's in der Nacht?","type":"dialogue","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Eben jetzt ruft der Nachtwächter Zwei an.","type":"dialogue","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Was? will diese Nacht nicht enden? Hörtest du keinen Tumult in der Nähe? Wo ist Kar – der Graf, will ich sagen?","type":"dialogue","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Alles wider mich verschworen?","type":"dialogue","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Gnädiger Herr!","type":"dialogue","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Nein! ich zittere nicht! Warum sollte ich zittern? Es war ledig ein Traum. Wer sagt, dass ich zittere.","type":"dialogue","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Ihr seid totenbleich, Eure Stimme ist bang und lallet.","type":"dialogue","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Ich habe das Fieber, ich habe das Fieber. Es war ledig ein Traum. Träume bedeuten nichts – nicht wahr, Daniel? Träume kommen ja aus dem Bauch, und Träume bedeuten nichts – ich hatte soeben einen lustigen Traum. (Er sinkt ohnmächtig nieder.)","type":"dialogue","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Was ist das?","type":"dialogue","page":55,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ  (richtet sich matt auf)","type":"speaker","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Wo bin ich? – du, Daniel? was hab' ich gesagt? merke nicht drauf! ich hab' eine Lüge gesagt, es sei, was es wolle – komm! hilf mir auf! – es ist nur ein Anstoß von Schwindel – weil ich – weil ich – nicht ausgeschlafen habe.","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Er hat den Verstand verloren. Ich will nach einem Arzt rufen.","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Bleib! setz dich. So – du bist ein gescheiter Mann, ein guter Mann.","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Ich will Euch zu Bette bringen, Ruhe ist Euch besser.","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Nein, ich bitte dich, lass dir erzählen und lache mich derb aus, was ich träumte. –","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Kann ich lachen, wenn mir die Haut schaudert? Träume kommen von Gott.","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Pfui doch, pfui doch, sage das nicht! Heiß mich einen Narren, einen aberwitzigen, abgeschmackten Narren! Tu das, lieber Daniel, ich bitte dich drum, spotte mich tüchtig aus!","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Träume kommen von Gott. Ich will für Euch beten.","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Es ist kein Gott! Ich sage dir: Es ist keiner!","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Stolze Seele.","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Mit dem letzten Blutstropfen zerrinnt auch Geist und Gedanke. Er macht alle Schwachheiten des Körpers mit, wird er nicht auch aufhören bei seiner Zerstörung? Siehe da! Das ist eure unsterbliche Seele!","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Ich will aber nicht unsterblich sein. Sag mir, was ist die größte Sünde, und die Ihn am grimmigsten aufbringt?","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Ich kenne nur zwei. Aber sie werden nicht von Menschen begangen, auch ahnden sie Menschen nicht.","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Diese zwei? –","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Vatermord heißt die eine, Brudermord die andere – Was macht Euch auf einmal so bleich?","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Was, Alter? Stehst du mit dem Himmel oder mit der Hölle im Bündnis? Wer hat dir das gesagt?","type":"dialogue","page":56,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Wehe Dem, der sie beide auf dem Herzen hat! Ihm wäre besser, dass er nie geboren wäre! Aber seid ruhig! Ihr habt weder Vater noch Bruder mehr!","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Ha! – was, du kennst keine drüber? Besinne dich– keine einzige drüber?","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Keine einzige drüber.","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ  (fällt in einen Stuhl) (Tumult)","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Stürmt, dort muss er sein.","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ  (auf den Knien)","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Höre mich beten, Gott im Himmel! Erhöre mich, Gott im Himmel!","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Mein doch! Was treibt Ihr? Das ist ja gottlos gebetet.","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Wo ist der Schwarz mit seinem Haufen? – Postier dich ums Schloss, Grimm – Lauf Sturm wider die Ringmauer!","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ  (betet)","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Ich bin kein gemeiner Mörder gewesen, mein Herrgott! – Ich kann nicht beten – hier, hier! (Auf Brust und Stirn schlagend.) (Steht auf.)","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Nein, ich will auch nicht beten – diesen Sieg soll der Himmel nicht haben, diesen Spott mir nicht antun die Hölle –","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Helft – rettet – das ganze Schloss steht in Flammen!","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Theaterfeuer, das keine Pfeife anzündet.","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Hier nimm diesen Degen. Hurtig! Jag mir ihn hinterrücks in den Bauch.","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"DANIEL","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Bewahre! Bewahre! Ich mag Niemand zu früh in den Himmel fördern…,","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"FRANZ","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"In die Hölle, wolltest du sagen – Wirklich? Ha! so erbarm du dich meiner! (Er reißt seine goldene Hutschnur ab und erdrosselt sich.)","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"SCHWEIZER  (mit seinen Leuten)","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Mordkanaille, wo bist du? – Wohin hat sich die Bestie verkrochen?","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"GRIMM","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Halt, was liegt hier im Weg?","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Steckt eure Schwerter ein, hier liegt er wie eine Katze verreckt.","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Tot! was? tot? ohne mich tot? – Erlogen, sag' ich – Gebt Acht, wie hurtig er auf die Beine springt! – (Rüttelt ihn.) Heh du! Es gibt einen Vater zu ermorden.","type":"dialogue","page":57,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"GRIMM","type":"speaker","page":58,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Gib dir keine Müh. Er ist mausetot.","type":"dialogue","page":58,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"SCHWEIZER","type":"speaker","page":58,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"Ja! Er freut sich nicht – Er ist mausetot – Gehet zurück und saget meinem Hauptmann: Er ist mausetot – mich sieht er nicht wieder. (Schießt sich vor die Stirn.)","type":"dialogue","page":58,"act":"FÜNFTER AKT","scene":"1. SZENE"},{"text":"2. SZENE","type":"scene","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Der Schauplatz wie in der letzten Scene des vorigen Akts.","type":"setting","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Der alte Moor auf einem Stein sitzend. Räuber Moor gegenüber. Räuber hin und her im Wald.","type":"setting","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Er kommt noch nicht?","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"O mein Kind!","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Was? – du weinst um ihn?","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Jetzt – jetzt wird mein Kind gerichtet!","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR  (erschrocken)","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Welches?","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Ha! was ist das für eine Frage?","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Nichts! nichts!","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Ja, ich habe einen Sohn gequält, und ein Sohn musste mich wieder quälen. O mein Karl! mein Karl! Vergib mir!","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR  (schnell)","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Er vergibt Euch. Wenn er's wert ist, Euer Sohn zu heißen – er muss Euch vergeben.","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Vater! Ich bin dein Karl!","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Nein, das ist nicht Karl.","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. Moor tritt beiseite. Die abgesandten ohne Schweizer treten auf.","type":"direction","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"GRIMM  (mit gesenktem Ton)","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Mein Hauptmann! (Räuber Moor antwortet nicht und tritt weiter zurück.)","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"SCHWARZ","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Teurer Hauptmann! (Räuber Moor weicht weiter zurück.)","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"GRIMM","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Wir sind unschuldig, mein Hauptmann.","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR  (ohne nach ihnen zu blicken)","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Wer seid ihr?","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"GRIMM","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Du blickst uns nicht an? Deine Getreuen.","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Weh euch, wenn ihr mir getreu wart!","type":"dialogue","page":59,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"GRIMM","type":"speaker","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Das letzte Lebewohl von deinem Knecht Schweizer – er kehrt nie wieder, dein Knecht Schweizer.","type":"dialogue","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR  (aufspringend)","type":"speaker","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"So habt ihr ihn nicht gefunden?","type":"dialogue","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"SCHWARZ","type":"speaker","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Tot gefunden.","type":"dialogue","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR  (froh emporhüpfend)","type":"speaker","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Hab Dank, Lenker der Dinge! – Umarmet mich, meine Kinder! – Erbarmung sei von nun an die Losung – Nun wär' auch das überstanden – Alles überstanden.","type":"dialogue","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"RÄUBER","type":"speaker","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Heisa, heisa! Ein Fang, ein superber Fang!","type":"dialogue","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"AMALIA  (mit fliegenden Haaren)","type":"speaker","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Die Toten, schreien sie, seien erstanden auf seine Mein Oheim lebendig – in diesem Wald – Wo ist er? Karl! Oheim! – Ha! (Stürzt auf den Alten zu.)","type":"dialogue","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Amalia! Meine Tochter! Amalia! (Hält sie in seinen Armen gepresst.)","type":"dialogue","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR  (zurückspringend)","type":"speaker","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Wer bringt dies Bild vor meine Augen?","type":"dialogue","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"AMALIA  (entspringt dem Alten, springt auf den Räuber zu und umschlingt ihn entzückt)","type":"speaker","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Ich habe ihn, o ihr Sterne! Ich habe ihn! –","type":"dialogue","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR  (sich losreißend, zu den Räubern)","type":"speaker","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Brecht auf, ihr!","type":"dialogue","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Wohin? was? Du fliehst? Bräutigam!","type":"dialogue","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"D. A. MOOR","type":"speaker","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Bräutigam? Tochter?","type":"dialogue","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Weg, weg! – Unglückseligste der Bräute! – Schau selbst, frage selbst, höre! – Unglückseligster der Väter! Zu spät! Frag mich nichts mehr. Vater! Ich bin, ich habe… Wer hat mich hergelockt? Wer von euch hat mich hierhergelockt? So vergeh denn, Amalia!","type":"dialogue","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Vater, stirb ein drittes Mal- durch mich! Diese deine Retter sind Räuber und Mörder. Dein Karl ist ihr Hauptmann!","type":"dialogue","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Der alte Moor gibt seinen Geist auf.","type":"direction","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Amalia steht stumm.","type":"direction","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Die ganze Räuberbande in fürchterlicher Pause.","type":"direction","page":60,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Was hab' ich getan? Ich habe Diesen geliebt.","type":"dialogue","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Mörder! Teufel! Ich kann dich Engel nicht lassen.","type":"dialogue","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR  (schleudert sie von sich)","type":"speaker","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Fort, falsche Schlange. (Amalia fällt ihm um den Hals.) Amalia! hast du vergessen? Weißt du auch, wen du umarmest, Amalia?","type":"dialogue","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Einziger, Unzertrennlicher!","type":"dialogue","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Sie vergibt mir, sie liebt mich! Der Friede meiner Seele ist wiedergekommen. O Amalia! Amalia! Amalia! (Er hängt an ihrem Mund, sie bleiben in stummer Umarmung.)","type":"dialogue","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"EIN RÄUBER  (grimmig hervortretend)","type":"speaker","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Halt ein, Verräter! –","type":"dialogue","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"EIN ALTER RÄUBER","type":"speaker","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Denk' an die böhmischen Wälder! Hörst du? zagst du? Treuloser, wo sind deine Schwüre? Vergisst man Wunden so bald? Da wir Glück, Ehre und Leben in die Schanzen schlugen für dich, da wir standen wie Mauern, auffingen wie Schilder die Hiebe, die einem Leben galten, – hubst du da nicht deine Hand zum eisernen Eid auf, schwurst, uns nie zu verlassen, wie wir dich nicht verlassen haben? – Ehrloser! Treuvergessener! und du willst abfallen, wenn eine Metze greint?","type":"dialogue","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"EIN DRITTER RÄUBER","type":"speaker","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Pfui, über den Meineid! Der Geist des geopferten Rollers, den du zum Zeugen aus dem Totenreich zwangst, wird erröten über deine Feigheit.","type":"dialogue","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"DIE RÄUBER","type":"speaker","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Schau her, schau! Kennst du diese Narben? Du bist unser! mit unserem Herzblut haben wir dich zum Leibeigenen angekauft, unser bist du. Opfer um Opfer! Amalia für die Bande!","type":"dialogue","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR  (lässt ihre Hand fahren)","type":"speaker","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Es ist aus! – Ich wollte umkehren und zu meinem Vater gehn, aber es soll nicht sein. (Kalt.) Blöder Tor ich, warum wollt' ich es auch? Kann denn ein großer Sünder noch umkehren? Kommt, Kameraden!","type":"dialogue","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"AMALIA  (reißt ihn zurück)","type":"speaker","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Halt, halt! Einen Stoß! einen Todesstoß! Neu verlassen! Zieh dein Schwert und erbarme dich!","type":"dialogue","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Ich töte dich nicht!","type":"dialogue","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Ich will ja nicht Liebe mehr – Tod ist meine Bitte nur. – Verlassen, verlassen! Nimm es ganz in seiner entsetzlichen Fülle, verlassen! Ich kann's nicht. Tod ist meine Bitte nur! Sieh, meine Hand zittert! Ich habe das Herz nicht, zu stoßen. Dir ist's ja so leicht, so leicht, bist ja Meister im Morden, zieh dein Schwert, und ich bin glücklich!","type":"dialogue","page":61,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Fort, ich töte kein Weib!","type":"dialogue","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Ha, du kannst nur die Glücklichen töten. Euer Meister ist ein eitler, feigherziger Prahler.","type":"dialogue","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Was sagst du? (Die Räuber wenden sich ab.)","type":"dialogue","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"AMALIA","type":"speaker","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Kein Freund? Auch unter diesen nicht ein Freund? (Sie steht auf.) Nun denn. (Sie will gehen, ein Räuber zielt.)","type":"dialogue","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Halt! Wag' es – Moors Geliebte soll nur durch Moor sterben! (Er ermordet sie.)","type":"dialogue","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"DIE RÄUBER","type":"speaker","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Hauptmann! Hauptmann! Was machst du? Bist du wahnsinnig geworden?","type":"dialogue","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Habt ihr noch was zu fordern? Ich hab' euch einen Engel geschlachtet. Wie, seht doch recht her! Seid ihr nunmehr zufrieden?","type":"dialogue","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"GRIMM","type":"speaker","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Du hast deine Schuld mit Wucher bezahlt. Du hast getan, was kein Mann würde für seine Ehre tun. Komm jetzt weiter!","type":"dialogue","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Sagst du das? Nicht wahr, das Leben einer Heiligen um das Leben der Schelmen, es ist ungleicher Tausch? (Mit bitterem Gelächter.) Die Narben, die böhmischen Wälder! Ja! ja, dies musste freilich bezahlt werden.","type":"dialogue","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"SCHWARZ","type":"speaker","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Sei ruhig, Hauptmann! Komm mit uns, der Anblick ist nicht für dich. Führe uns weiter.","type":"dialogue","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Halt – noch ein Wort, eh wir weiter gehn – Mit Scham und Grauen leg' ich hier diesen blutigen Stab nieder. – Wir wollen ewig niemals gemeine Sache machen.","type":"dialogue","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"RÄUBER","type":"speaker","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Ha, Mutloser! wo sind deine hochfliegenden Pläne?","type":"dialogue","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Ich wollte Welt durch Gräuel verschönern und die Gesetze durch Gesetzlosigkeit aufrecht halten! Ich nannte es Rache und Recht – da steh' ich am Rand eines entsetzlichen Lebens und erfahre, dass zwei Menschen, wie ich, den ganzen Bau der sittlichen Welt zu Grunde richten würden.","type":"dialogue","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"RÄUBER","type":"speaker","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Nehmt ihm den Degen weg – er will sich umbringen.","type":"dialogue","page":62,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":63,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Toren ihr! Er soll mich lebendig haben. Ich geh', mich selbst in die Hände der Justiz zu überliefern.","type":"dialogue","page":63,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"RÄUBER","type":"speaker","page":63,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Er will sein Leben an eitle Bewunderung setzen.","type":"dialogue","page":63,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"R. MOOR","type":"speaker","page":63,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"Man könnte mich darum bewundern. (Nach einigem Nachsinnen.) Ich erinnere mich, einen armen Schelm gesprochen zu haben, als ich herüberkam, der im Taglohn arbeitet und elf lebendige Kinder hat – Man hat tausend Louisdore geboten, wer den großen Räuber lebendig liefert. Dem Mann kann geholfen werden. (Er geht ab.)","type":"dialogue","page":63,"act":"FÜNFTER AKT","scene":"2. SZENE"},{"text":"ENDE","type":"end","page":63,"act":"FÜNFTER AKT","scene":"2. SZENE"}]};
window.loadTheaterScript=async()=>window.THEATER_SCRIPT;
